/**
 * MMS Application Root
 *
 * Main application component that assembles the layout and provides
 * state management context via @belt/tools machine.
 *
 * @see specs/006-user-interface.md Section 6.2 Application Layout
 */

import { Classes, OverlaysProvider } from '@blueprintjs/core';

import { Header, Toolbar, Sidebar, StatusBar, InfiniteCanvas } from './components';
import { useUi } from './store';
import type { UiSliceState } from './store/slices/ui';

import './App.css';

function AppContent() {
  const { state: uiStateRaw } = useUi();
  const uiState = uiStateRaw as unknown as UiSliceState;

  // Apply theme class to body
  const themeClass = uiState.theme === 'dark' ? Classes.DARK : '';

  return (
    <div className={`mms-app ${themeClass}`}>
      {/* Fixed Header */}
      <Header />

      {/* Main Container (below header) */}
      <div className="mms-main">
        {/* Toolbar */}
        <Toolbar />

        {/* Content Area */}
        <div className="mms-content">
          {/* Left Sidebar - Train List */}
          <Sidebar />

          {/* Main Canvas Area */}
          <InfiniteCanvas />
        </div>

        {/* Status Bar */}
        <StatusBar />
      </div>
    </div>
  );
}

function App() {
  return (
    <OverlaysProvider>
      <AppContent />
    </OverlaysProvider>
  );
}

export default App;

/**
 * MMS Application Header
 *
 * Top navigation bar with logo, fleet/depot filters, search, and user menu.
 * Based on specs/006-user-interface.md Section 6.2.
 */

import {
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Button,
  HTMLSelect,
  InputGroup,
  Menu,
  MenuItem,
  MenuDivider,
  Popover,
  Classes,
} from '@blueprintjs/core';

import { useFleet, useUi } from '../../store';
import type { FleetSliceState } from '../../store/slices/fleet';
import type { UiSliceState } from '../../store/slices/ui';

export function Header() {
  const { state: fleetStateRaw, actions: fleetActions } = useFleet();
  const { state: uiStateRaw, actions: uiActions } = useUi();

  const fleetState = fleetStateRaw as unknown as FleetSliceState;
  const uiState = uiStateRaw as unknown as UiSliceState;

  const fleetOptions = [
    { value: '', label: 'All Fleets' },
    ...fleetState.fleets.map((fleet) => ({
      value: fleet.id,
      label: `${fleet.code} - ${fleet.name}`,
    })),
  ];

  const depotOptions = [
    { value: '', label: 'All Depots' },
    ...fleetState.depots.map((depot) => ({
      value: depot.id,
      label: `${depot.code} - ${depot.name}`,
    })),
  ];

  const handleFleetChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const fleetId = event.target.value;
    fleetActions.setFleetFilter(fleetId ? [fleetId] : []);
  };

  const handleDepotChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const depotId = event.target.value;
    fleetActions.setDepotFilter(depotId ? [depotId] : []);
  };

  const handleSearchChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    fleetActions.setSearchTerm(event.target.value);
  };

  const handleThemeToggle = () => {
    const nextTheme = uiState.theme === 'dark' ? 'light' : 'dark';
    uiActions.setTheme(nextTheme);
  };

  const selectedFleetId = fleetState.filters.fleetIds[0] || '';
  const selectedDepotId = fleetState.filters.depotIds[0] || '';

  const userMenu = (
    <Menu>
      <MenuItem icon="user" text="Profile" />
      <MenuItem icon="cog" text="Settings" />
      <MenuDivider />
      <MenuItem icon="log-out" text="Logout" intent="danger" />
    </Menu>
  );

  return (
    <Navbar className="mms-header" fixedToTop>
      <NavbarGroup>
        <NavbarHeading>
          <span className="mms-logo" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor">
              <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5" />
            </svg>
            <strong>MMS</strong>
          </span>
        </NavbarHeading>

        <NavbarDivider />

        <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
          <label className={Classes.TEXT_MUTED} style={{ fontSize: '12px' }}>
            Fleet:
          </label>
          <HTMLSelect
            minimal
            options={fleetOptions}
            value={selectedFleetId}
            onChange={handleFleetChange}
          />

          <label className={Classes.TEXT_MUTED} style={{ fontSize: '12px' }}>
            Depot:
          </label>
          <HTMLSelect
            minimal
            options={depotOptions}
            value={selectedDepotId}
            onChange={handleDepotChange}
          />
        </div>
      </NavbarGroup>

      <NavbarGroup align="right">
        <InputGroup
          leftIcon="search"
          placeholder="Search trains..."
          value={fleetState.filters.searchTerm}
          onChange={handleSearchChange}
          style={{ width: '200px' }}
        />

        <NavbarDivider />

        <Button
          minimal
          icon={uiState.theme === 'dark' ? 'flash' : 'moon'}
          title="Toggle theme"
          onClick={handleThemeToggle}
        />

        <Button
          minimal
          icon="notifications"
          title="Notifications"
        />

        <NavbarDivider />

        <Popover content={userMenu} placement="bottom-end">
          <Button minimal icon="user" rightIcon="caret-down" text="User" />
        </Popover>
      </NavbarGroup>
    </Navbar>
  );
}

