/**
 * MMS Toolbar
 *
 * View controls, navigation, and action buttons.
 * Based on specs/006-user-interface.md Section 6.2.
 */

import {
  Button,
  ButtonGroup,
  Divider,
  Popover,
  Menu,
  MenuItem,
  Tag,
} from '@blueprintjs/core';
import { format } from 'date-fns';

import { useCanvas, useScenario, useUi } from '../../store';
import type { CanvasSliceState } from '../../store/slices/canvas';
import type { ScenarioSliceState } from '../../store/slices/scenario';
import type { UiSliceState } from '../../store/slices/ui';

export function Toolbar() {
  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
  const { state: scenarioStateRaw } = useScenario();
  const { state: uiStateRaw, actions: uiActions } = useUi();

  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;
  const uiState = uiStateRaw as unknown as UiSliceState;

  const handleZoomLevelClick = (level: 'STRATEGIC' | 'TACTICAL' | 'OPERATIONAL') => {
    const targetZoom =
      level === 'STRATEGIC' ? 2 :
      level === 'TACTICAL' ? 10 :
      level === 'OPERATIONAL' ? 14 : 10;

    canvasActions.setZoom(targetZoom);
  };

  const handleZoomIn = () => {
    canvasActions.setZoom(Math.min(20, canvasState.zoom + 1));
  };

  const handleZoomOut = () => {
    canvasActions.setZoom(Math.max(0, canvasState.zoom - 1));
  };

  const handleToday = () => {
    canvasActions.goToToday();
  };

  const handlePrevPeriod = () => {
    const start = new Date(canvasState.viewport.startDate);
    const periodDays = canvasState.zoomLevel === 'STRATEGIC' ? 365 :
                       canvasState.zoomLevel === 'TACTICAL_WIDE' ? 90 :
                       canvasState.zoomLevel === 'TACTICAL' ? 28 : 7;
    start.setDate(start.getDate() - periodDays);
    canvasActions.setViewport({
      startDate: start.toISOString().split('T')[0],
    });
  };

  const handleNextPeriod = () => {
    const start = new Date(canvasState.viewport.startDate);
    const periodDays = canvasState.zoomLevel === 'STRATEGIC' ? 365 :
                       canvasState.zoomLevel === 'TACTICAL_WIDE' ? 90 :
                       canvasState.zoomLevel === 'TACTICAL' ? 28 : 7;
    start.setDate(start.getDate() + periodDays);
    canvasActions.setViewport({
      startDate: start.toISOString().split('T')[0],
    });
  };

  const handleToggleLayer = (layer: 'complianceWindows' | 'manhourOverlay' | 'driftOverlay' | 'baselineShadow') => {
    canvasActions.toggleLayer(layer);
  };

  const handlePublishBaseline = () => {
    uiActions.openModal({ type: 'PUBLISH_BASELINE' });
  };

  const handleCreateScenario = () => {
    uiActions.openModal({ type: 'CREATE_SCENARIO' });
  };

  const handleRunOptimizer = () => {
    uiActions.openModal({ type: 'RUN_OPTIMIZER' });
  };

  const overlayMenu = (
    <Menu>
      <MenuItem
        icon={canvasState.layers.complianceWindows ? 'tick' : 'blank'}
        text="Compliance Windows"
        onClick={() => handleToggleLayer('complianceWindows')}
      />
      <MenuItem
        icon={canvasState.layers.manhourOverlay ? 'tick' : 'blank'}
        text="Man-hour Utilization"
        onClick={() => handleToggleLayer('manhourOverlay')}
      />
      <MenuItem
        icon={canvasState.layers.driftOverlay ? 'tick' : 'blank'}
        text="Drift Analysis"
        onClick={() => handleToggleLayer('driftOverlay')}
      />
      <MenuItem
        icon={canvasState.layers.baselineShadow ? 'tick' : 'blank'}
        text="Baseline Shadow"
        onClick={() => handleToggleLayer('baselineShadow')}
      />
    </Menu>
  );

  const exportMenu = (
    <Menu>
      <MenuItem icon="document" text="Export PM Schedule (Excel)" />
      <MenuItem icon="document" text="Generate Report (PDF)" />
    </Menu>
  );

  const isStrategic = canvasState.zoomLevel === 'STRATEGIC' || canvasState.zoomLevel === 'TACTICAL_WIDE';
  const isTactical = canvasState.zoomLevel === 'TACTICAL';
  const isOperational = canvasState.zoomLevel === 'OPERATIONAL' || canvasState.zoomLevel === 'DETAIL';

  return (
    <div className="mms-toolbar" style={{
      display: 'flex',
      justifyContent: 'space-between',
      padding: '8px 16px',
      borderBottom: '1px solid var(--pt-divider-black, #e1e8ed)',
      backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
    }}>
      <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
        {/* Zoom Level Buttons */}
        <ButtonGroup>
          <Button
            text="Strategic"
            active={isStrategic}
            onClick={() => handleZoomLevelClick('STRATEGIC')}
          />
          <Button
            text="Tactical"
            active={isTactical}
            onClick={() => handleZoomLevelClick('TACTICAL')}
          />
          <Button
            text="Operational"
            active={isOperational}
            onClick={() => handleZoomLevelClick('OPERATIONAL')}
          />
        </ButtonGroup>

        <Divider />

        {/* Navigation */}
        <ButtonGroup>
          <Button icon="chevron-left" onClick={handlePrevPeriod} />
          <Button text="Today" onClick={handleToday} />
          <Button icon="chevron-right" onClick={handleNextPeriod} />
        </ButtonGroup>

        <Tag minimal style={{ fontFamily: 'monospace' }}>
          {format(new Date(canvasState.viewport.startDate), 'MMM yyyy')}
        </Tag>

        <Divider />

        {/* Zoom Controls */}
        <ButtonGroup>
          <Button icon="zoom-out" onClick={handleZoomOut} disabled={canvasState.zoom <= 0} />
          <Button icon="zoom-in" onClick={handleZoomIn} disabled={canvasState.zoom >= 20} />
        </ButtonGroup>

        <Tag minimal intent="primary">
          {canvasState.zoomLevel.replace('_', ' ')}
        </Tag>
      </div>

      <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
        {/* Scenario Indicator */}
        {scenarioState.activeScenarioId && (
          <Tag intent="warning" icon="annotation">
            Scenario Active
          </Tag>
        )}

        {/* Actions */}
        <Button
          icon="git-commit"
          text="Publish Baseline"
          onClick={handlePublishBaseline}
        />

        <Button
          icon="fork"
          text="Create Scenario"
          onClick={handleCreateScenario}
        />

        <Button
          intent="primary"
          icon="play"
          text="Run Optimizer"
          onClick={handleRunOptimizer}
          loading={uiState.loading.optimizer}
        />

        <Divider />

        {/* Overlays */}
        <Popover content={overlayMenu} placement="bottom-end">
          <Button icon="layers" text="Overlays" rightIcon="caret-down" />
        </Popover>

        {/* Export */}
        <Popover content={exportMenu} placement="bottom-end">
          <Button icon="export" text="Export" rightIcon="caret-down" />
        </Popover>

        {/* Help */}
        <Button
          minimal
          icon="help"
          onClick={() => uiActions.toggleHelpPanel()}
        />
      </div>
    </div>
  );
}

/**
 * MMS Status Bar
 *
 * Bottom status bar showing baseline info, drift alerts, sync status.
 * Based on specs/006-user-interface.md Section 6.2.
 */

import {
  Icon,
  Tag,
  Intent,
  Popover,
  Menu,
  MenuItem,
  MenuDivider,
  Classes,
} from '@blueprintjs/core';
import { format, formatDistanceToNow } from 'date-fns';

import { useScenario, useUi } from '../../store';
import { DRIFT_COLORS } from '../theme';
import type { ScenarioSliceState } from '../../store/slices/scenario';
import type { UiSliceState } from '../../store/slices/ui';

export function StatusBar() {
  const { state: scenarioStateRaw } = useScenario();
  const { state: uiStateRaw } = useUi();

  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;
  const uiState = uiStateRaw as unknown as UiSliceState;

  // Compute drift summary
  const trainsRequiringReplan = scenarioState.driftAnalysis.filter(d => d.requiresReplan).length;
  const driftSeverity = trainsRequiringReplan > 10 ? 'critical' :
                        trainsRequiringReplan > 5 ? 'warning' : 'ok';

  // Active baseline info
  const activeBaseline = scenarioState.baselines.find(b => b.id === scenarioState.activeBaselineId);

  // Connection status
  const isConnected = uiState.isOnline && uiState.websocketConnected;
  const connectionIntent: Intent = isConnected ? 'success' : 'danger';

  // Sync status
  const lastSyncText = uiState.lastSyncAt
    ? formatDistanceToNow(uiState.lastSyncAt, { addSuffix: true })
    : 'Never';

  // Active jobs
  const runningJobs = uiState.optimizerJobs.filter(j => j.status === 'RUNNING');

  const baselineMenu = (
    <Menu>
      <MenuItem disabled text={`Version: ${activeBaseline?.version || 'N/A'}`} />
      <MenuItem disabled text={`Published: ${activeBaseline?.publishedAt ? format(new Date(activeBaseline.publishedAt), 'MMM d, yyyy') : 'N/A'}`} />
      <MenuDivider />
      <MenuItem icon="history" text="View Baseline History" />
      <MenuItem icon="comparison" text="Compare to Previous" />
    </Menu>
  );

  const driftMenu = (
    <Menu>
      {scenarioState.driftAnalysis.filter(d => d.requiresReplan).slice(0, 5).map(drift => (
        <MenuItem
          key={drift.trainId}
          icon="warning-sign"
          text={`Train ${drift.trainNumber}: ${drift.mileageDriftPct.toFixed(1)}% drift`}
          intent="warning"
        />
      ))}
      {trainsRequiringReplan > 5 && (
        <MenuItem disabled text={`... and ${trainsRequiringReplan - 5} more`} />
      )}
      <MenuDivider />
      <MenuItem icon="refresh" text="Refresh Drift Analysis" />
      <MenuItem icon="document" text="View Full Report" />
    </Menu>
  );

  const jobsMenu = (
    <Menu>
      {runningJobs.map(job => (
        <MenuItem
          key={job.id}
          icon="refresh"
          text={`${job.type}: ${job.progress}%`}
          labelElement={<Tag minimal>{job.status}</Tag>}
        />
      ))}
      {runningJobs.length === 0 && (
        <MenuItem disabled text="No active jobs" />
      )}
      <MenuDivider />
      <MenuItem icon="history" text="View Job History" />
    </Menu>
  );

  return (
    <div className="mms-status-bar" style={{
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      padding: '6px 16px',
      borderTop: '1px solid var(--pt-divider-black, #e1e8ed)',
      backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
      fontSize: '12px',
    }}>
      {/* Left Section - Baseline & Drift */}
      <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }}>
        <Popover content={baselineMenu} placement="top-start" interactionKind="hover">
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px', cursor: 'pointer' }}>
            <Icon icon="git-commit" size={12} />
            <span className={Classes.TEXT_MUTED}>Baseline:</span>
            <span style={{ fontWeight: 500 }}>
              {activeBaseline ? `${activeBaseline.name} v${activeBaseline.version}` : 'No baseline'}
            </span>
          </div>
        </Popover>

        {trainsRequiringReplan > 0 && (
          <Popover content={driftMenu} placement="top" interactionKind="hover">
            <Tag
              intent={driftSeverity === 'critical' ? 'danger' : driftSeverity === 'warning' ? 'warning' : 'success'}
              icon="warning-sign"
              interactive
              style={{ cursor: 'pointer' }}
            >
              Drift: {trainsRequiringReplan} train{trainsRequiringReplan !== 1 ? 's' : ''} need attention
            </Tag>
          </Popover>
        )}

        {trainsRequiringReplan === 0 && (
          <Tag intent="success" icon="tick-circle">
            All trains on track
          </Tag>
        )}
      </div>

      {/* Center Section - Active Scenario */}
      {scenarioState.activeScenarioId && (
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
          <Tag intent="warning" icon="fork">
            Scenario: {scenarioState.scenarios.find(s => s.id === scenarioState.activeScenarioId)?.name || 'Active'}
          </Tag>
          <span className={Classes.TEXT_MUTED}>
            {scenarioState.activeDeltas.length} change{scenarioState.activeDeltas.length !== 1 ? 's' : ''}
          </span>
        </div>
      )}

      {/* Right Section - Sync & Connection Status */}
      <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
        {/* Running Jobs */}
        {runningJobs.length > 0 && (
          <Popover content={jobsMenu} placement="top-end" interactionKind="hover">
            <Tag intent="primary" icon="refresh" interactive>
              {runningJobs.length} job{runningJobs.length !== 1 ? 's' : ''} running
            </Tag>
          </Popover>
        )}

        {/* Last Sync */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
          <Icon icon="refresh" size={12} color={uiState.syncInProgress ? '#137cbd' : undefined} />
          <span className={Classes.TEXT_MUTED}>
            {uiState.syncInProgress ? 'Syncing...' : `Last sync: ${lastSyncText}`}
          </span>
        </div>

        {/* Connection Status */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
          <Icon
            icon={isConnected ? 'cell-tower' : 'disable'}
            size={12}
            intent={connectionIntent}
          />
          <span style={{ color: isConnected ? DRIFT_COLORS.ok : DRIFT_COLORS.critical }}>
            {isConnected ? 'Connected' : 'Offline'}
          </span>
        </div>
      </div>
    </div>
  );
}

