/**
 * Tactical Gantt Layer
 *
 * Konva-based Gantt chart layer for tactical PM scheduling (zoom levels 8-12).
 * Renders PM blocks, constraint walls, train labels, and timeline axis.
 *
 * Features:
 * - PM blocks with status-based colors
 * - Compliance window constraint walls
 * - Train labels on the left
 * - Week/day timeline axis at top
 * - Drag-and-drop PM rescheduling (with constraint validation)
 * - Hover tooltips
 *
 * @see specs/006-user-interface.md Section 6.3.3
 */

import { useRef } from 'react';
import { Stage, Layer, Rect, Text, Line, Group } from 'react-konva';
import type { KonvaEventObject } from 'konva/lib/Node';
import type { Stage as StageType } from 'konva/lib/Stage';

import type { PmBlock, ConstraintWall, TacticalCanvasData, DragValidationState } from './types';
import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';

// =============================================================================
// Constants
// =============================================================================

/** Layout constants for the Gantt chart */
const LAYOUT = {
  HEADER_HEIGHT: 48,
  TRAIN_LABEL_WIDTH: 120,
  ROW_HEIGHT: 40,
  PM_BLOCK_HEIGHT: 28,
  PM_BLOCK_MARGIN: 6,
  DAY_WIDTH: 24,
  WEEK_WIDTH: 24 * 7,
  MIN_PM_WIDTH: 20,
  CONSTRAINT_WALL_WIDTH: 2,
  GRID_LINE_COLOR: '#e2e8f0',
  HEADER_BG: '#f8fafc',
  TRAIN_LABEL_BG: '#ffffff',
  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
};

/** PM status to color mapping */
function getPmColor(status: string): string {
  switch (status) {
    case 'SCHEDULED':
      return PM_STATUS_COLORS.scheduled;
    case 'IN_PROGRESS':
      return PM_STATUS_COLORS.inProgress;
    case 'COMPLETED':
      return PM_STATUS_COLORS.completed;
    case 'CANCELLED':
      return PM_STATUS_COLORS.cancelled;
    case 'DEFERRED':
      return PM_STATUS_COLORS.deferred;
    default:
      return PM_STATUS_COLORS.scheduled;
  }
}

// =============================================================================
// Types
// =============================================================================

export interface TacticalGanttLayerProps {
  data: TacticalCanvasData | null;
  trainOrder: string[];
  fromDate: Date;
  toDate: Date;
  width: number;
  height: number;
  selectedPmIds: string[];
  /** ID of the PM currently being dragged (if any) */
  draggingPmId?: string | null;
  /** Validation state for the current drag operation */
  dragValidation?: DragValidationState | null;
  onPmClick?: (pmId: string) => void;
  onPmHover?: (pm: PmBlock | null) => void;
  /** Called when drag starts - includes source date */
  onPmDragStart?: (pmId: string, sourceDate: string) => void;
  /** Called during drag as position changes - for real-time validation */
  onPmDragMove?: (pmId: string, targetDate: string) => void;
  /** Called when drag ends - for final commit/cancel */
  onPmDragEnd?: (pmId: string, newDate: string) => void;
  showConstraintWalls?: boolean;
  showGrid?: boolean;
}

interface DayData {
  date: Date;
  dateStr: string;
  dayOfWeek: number;
  isWeekStart: boolean;
  isToday: boolean;
}

interface WeekData {
  weekStart: Date;
  weekNum: number;
  daysInWeek: number;
}

// =============================================================================
// Pure Utility Functions
// =============================================================================

function getDays(fromDate: Date, toDate: Date): DayData[] {
  const days: DayData[] = [];
  const current = new Date(fromDate);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  while (current <= toDate) {
    const dayOfWeek = current.getDay();
    days.push({
      date: new Date(current),
      dateStr: current.toISOString().split('T')[0],
      dayOfWeek,
      isWeekStart: dayOfWeek === 0,
      isToday: current.getTime() === today.getTime(),
    });
    current.setDate(current.getDate() + 1);
  }
  return days;
}

function getWeeks(days: DayData[]): WeekData[] {
  const weeks: WeekData[] = [];
  let currentWeek: WeekData | null = null;

  for (const day of days) {
    if (day.isWeekStart || currentWeek === null) {
      if (currentWeek) {
        weeks.push(currentWeek);
      }
      const weekNum = getWeekNumber(day.date);
      currentWeek = { weekStart: day.date, weekNum, daysInWeek: 1 };
    } else {
      currentWeek.daysInWeek++;
    }
  }
  if (currentWeek) {
    weeks.push(currentWeek);
  }
  return weeks;
}

function getWeekNumber(date: Date): number {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
}

function dateDiffDays(a: Date, b: Date): number {
  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
}

function parseDate(dateStr: string): Date {
  return new Date(dateStr + 'T00:00:00');
}

function buildTrainIndexMap(trainOrder: string[]): Map<string, number> {
  const map = new Map<string, number>();
  trainOrder.forEach((id, i) => map.set(id, i));
  return map;
}

function buildTrainMetadata(pmBlocks: PmBlock[]): { numbers: Map<string, string>; fleets: Map<string, string> } {
  const numbers = new Map<string, string>();
  const fleets = new Map<string, string>();

  for (const pm of pmBlocks) {
    if (!numbers.has(pm.trainId)) {
      numbers.set(pm.trainId, pm.trainNumber);
      const code = pm.trainNumber.split('-')[0] || 'KS';
      fleets.set(pm.trainId, code);
    }
  }

  return { numbers, fleets };
}

// =============================================================================
// Sub-Components
// =============================================================================

interface TimelineHeaderProps {
  days: DayData[];
  weeks: WeekData[];
  offsetX: number;
}

function TimelineHeader({ days, weeks, offsetX }: TimelineHeaderProps) {
  return (
    <Group x={offsetX} y={0}>
      {/* Week row */}
      <Rect
        x={0}
        y={0}
        width={days.length * LAYOUT.DAY_WIDTH}
        height={LAYOUT.HEADER_HEIGHT / 2}
        fill={LAYOUT.HEADER_BG}
      />
      {weeks.map((week, i) => {
        const x = days.findIndex((d) => d.date.getTime() === week.weekStart.getTime()) * LAYOUT.DAY_WIDTH;
        const width = week.daysInWeek * LAYOUT.DAY_WIDTH;
        return (
          <Group key={i} x={x} y={0}>
            <Rect
              width={width}
              height={LAYOUT.HEADER_HEIGHT / 2}
              stroke={LAYOUT.GRID_LINE_COLOR}
              strokeWidth={1}
            />
            <Text
              x={4}
              y={6}
              text={`Week ${week.weekNum}`}
              fontSize={11}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#64748b"
            />
          </Group>
        );
      })}

      {/* Day row */}
      {days.map((day, i) => (
        <Group key={day.dateStr} x={i * LAYOUT.DAY_WIDTH} y={LAYOUT.HEADER_HEIGHT / 2}>
          <Rect
            width={LAYOUT.DAY_WIDTH}
            height={LAYOUT.HEADER_HEIGHT / 2}
            fill={day.isToday ? '#dbeafe' : day.dayOfWeek === 0 || day.dayOfWeek === 6 ? '#f1f5f9' : LAYOUT.HEADER_BG}
            stroke={LAYOUT.GRID_LINE_COLOR}
            strokeWidth={0.5}
          />
          <Text
            x={2}
            y={6}
            text={['S', 'M', 'T', 'W', 'T', 'F', 'S'][day.dayOfWeek]}
            fontSize={9}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill={day.isToday ? '#2563eb' : '#94a3b8'}
          />
          <Text
            x={2}
            y={15}
            text={String(day.date.getDate())}
            fontSize={9}
            fontFamily={LAYOUT.FONT_FAMILY}
            fill={day.isToday ? '#2563eb' : '#64748b'}
            fontStyle={day.isToday ? 'bold' : 'normal'}
          />
        </Group>
      ))}
    </Group>
  );
}

interface TrainLabelsPanelProps {
  trainOrder: string[];
  trainNumbers: Map<string, string>;
  fleetCodes: Map<string, string>;
}

function TrainLabelsPanel({ trainOrder, trainNumbers, fleetCodes }: TrainLabelsPanelProps) {
  return (
    <Group x={0} y={LAYOUT.HEADER_HEIGHT}>
      <Rect
        width={LAYOUT.TRAIN_LABEL_WIDTH}
        height={trainOrder.length * LAYOUT.ROW_HEIGHT}
        fill={LAYOUT.TRAIN_LABEL_BG}
      />
      {trainOrder.map((trainId, i) => {
        const trainNumber = trainNumbers.get(trainId) || trainId.slice(0, 8);
        const fleetCode = fleetCodes.get(trainId) || 'KS';
        const fleetColor = FLEET_COLORS[fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;

        return (
          <Group key={trainId} y={i * LAYOUT.ROW_HEIGHT}>
            <Rect
              width={LAYOUT.TRAIN_LABEL_WIDTH}
              height={LAYOUT.ROW_HEIGHT}
              stroke={LAYOUT.GRID_LINE_COLOR}
              strokeWidth={0.5}
            />
            <Rect
              x={4}
              y={10}
              width={4}
              height={LAYOUT.ROW_HEIGHT - 20}
              fill={fleetColor}
              cornerRadius={2}
            />
            <Text
              x={14}
              y={12}
              text={trainNumber}
              fontSize={12}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#1e293b"
              fontStyle="bold"
            />
            <Text
              x={14}
              y={26}
              text={fleetCode}
              fontSize={10}
              fontFamily={LAYOUT.FONT_FAMILY}
              fill="#64748b"
            />
          </Group>
        );
      })}
    </Group>
  );
}

interface GanttGridProps {
  days: DayData[];
  rowCount: number;
  offsetX: number;
}

function GanttGrid({ days, rowCount, offsetX }: GanttGridProps) {
  const weekStartDays = days.filter((d) => d.isWeekStart);
  const todayIndex = days.findIndex((d) => d.isToday);

  return (
    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
      {/* Row backgrounds */}
      {Array.from({ length: rowCount }).map((_, i) => (
        <Rect
          key={i}
          y={i * LAYOUT.ROW_HEIGHT}
          width={days.length * LAYOUT.DAY_WIDTH}
          height={LAYOUT.ROW_HEIGHT}
          fill={i % 2 === 0 ? '#ffffff' : '#fafafa'}
          stroke={LAYOUT.GRID_LINE_COLOR}
          strokeWidth={0.5}
        />
      ))}

      {/* Day columns - today highlight */}
      {todayIndex >= 0 && (
        <Rect
          x={todayIndex * LAYOUT.DAY_WIDTH}
          y={0}
          width={LAYOUT.DAY_WIDTH}
          height={rowCount * LAYOUT.ROW_HEIGHT}
          fill="rgba(37, 99, 235, 0.05)"
        />
      )}

      {/* Week separators */}
      {weekStartDays.map((day) => {
        const x = days.indexOf(day) * LAYOUT.DAY_WIDTH;
        return (
          <Line
            key={`week-${day.dateStr}`}
            points={[x, 0, x, rowCount * LAYOUT.ROW_HEIGHT]}
            stroke="#cbd5e1"
            strokeWidth={1}
          />
        );
      })}

      {/* Today line */}
      {todayIndex >= 0 && (
        <Line
          points={[
            todayIndex * LAYOUT.DAY_WIDTH,
            0,
            todayIndex * LAYOUT.DAY_WIDTH,
            rowCount * LAYOUT.ROW_HEIGHT,
          ]}
          stroke="#2563eb"
          strokeWidth={2}
          dash={[4, 4]}
        />
      )}
    </Group>
  );
}

interface PmBlockRectProps {
  pm: PmBlock;
  x: number;
  y: number;
  width: number;
  isSelected: boolean;
  isDragging?: boolean;
  dragValidation?: DragValidationState | null;
  onHover?: (pm: PmBlock | null) => void;
  onClick?: (pmId: string) => void;
  onDragStart?: (pmId: string, sourceDate: string) => void;
  onDragMove?: (pmId: string, targetDate: string) => void;
  onDragEnd?: (pmId: string, newDate: string) => void;
  fromDate: Date;
}

function PmBlockRect({
  pm,
  x,
  y,
  width,
  isSelected,
  isDragging,
  dragValidation,
  onHover,
  onClick,
  onDragStart,
  onDragMove,
  onDragEnd,
  fromDate,
}: PmBlockRectProps) {
  const color = pm.displayColor || getPmColor(pm.status);
  const finalWidth = Math.max(width, LAYOUT.MIN_PM_WIDTH);

  const handleDragStart = () => {
    if (onDragStart) {
      onDragStart(pm.pmId, pm.targetDate);
    }
  };

  const handleDragMove = (e: KonvaEventObject<DragEvent>) => {
    if (onDragMove) {
      const newX = e.target.x();
      const dayOffset = Math.round(newX / LAYOUT.DAY_WIDTH);
      const newDate = new Date(fromDate);
      newDate.setDate(newDate.getDate() + dayOffset);
      onDragMove(pm.pmId, newDate.toISOString().split('T')[0]);
    }
  };

  const handleDragEnd = (e: KonvaEventObject<DragEvent>) => {
    if (onDragEnd) {
      const newX = e.target.x();
      const dayOffset = Math.round(newX / LAYOUT.DAY_WIDTH);
      const newDate = new Date(fromDate);
      newDate.setDate(newDate.getDate() + dayOffset);
      onDragEnd(pm.pmId, newDate.toISOString().split('T')[0]);
    }
  };

  // Determine border color based on drag validation state
  let borderColor = isSelected ? '#1d4ed8' : '#00000015';
  let borderWidth = 1;
  let shadowBlur = 2;

  if (isDragging && dragValidation) {
    if (dragValidation.isValid) {
      // Valid drop - green outline
      borderColor = '#22c55e'; // Green-500
      borderWidth = 3;
      shadowBlur = 8;
    } else {
      // Invalid drop - red outline
      borderColor = '#ef4444'; // Red-500
      borderWidth = 3;
      shadowBlur = 8;
    }
  }

  return (
    <Group
      x={x}
      y={y}
      draggable={!pm.isLocked}
      onDragStart={handleDragStart}
      onDragMove={handleDragMove}
      onDragEnd={handleDragEnd}
      onMouseEnter={() => onHover?.(pm)}
      onMouseLeave={() => onHover?.(null)}
      onClick={() => onClick?.(pm.pmId)}
    >
      {/* Shadow for selected or dragging */}
      {(isSelected || isDragging) && (
        <Rect
          x={-3}
          y={-3}
          width={finalWidth + 6}
          height={LAYOUT.PM_BLOCK_HEIGHT + 6}
          fill="transparent"
          stroke={isDragging && dragValidation
            ? (dragValidation.isValid ? '#22c55e' : '#ef4444')
            : '#3b82f6'
          }
          strokeWidth={isDragging ? 3 : 2}
          cornerRadius={6}
          dash={isDragging ? undefined : undefined}
          opacity={isDragging ? 0.8 : 1}
        />
      )}

      {/* Drag validation indicator glow */}
      {isDragging && dragValidation && (
        <Rect
          x={-6}
          y={-6}
          width={finalWidth + 12}
          height={LAYOUT.PM_BLOCK_HEIGHT + 12}
          fill="transparent"
          stroke={dragValidation.isValid ? 'rgba(34, 197, 94, 0.3)' : 'rgba(239, 68, 68, 0.3)'}
          strokeWidth={8}
          cornerRadius={10}
        />
      )}

      {/* PM block */}
      <Rect
        width={finalWidth}
        height={LAYOUT.PM_BLOCK_HEIGHT}
        fill={color}
        stroke={borderColor}
        strokeWidth={borderWidth}
        cornerRadius={4}
        shadowColor={isDragging ? (dragValidation?.isValid ? '#22c55e' : '#ef4444') : '#000'}
        shadowBlur={shadowBlur}
        shadowOpacity={isDragging ? 0.4 : 0.1}
        shadowOffsetY={isDragging ? 4 : 1}
      />

      {/* Lock indicator */}
      {pm.isLocked && (
        <Text
          x={4}
          y={7}
          text="🔒"
          fontSize={10}
        />
      )}

      {/* PM code label */}
      <Text
        x={pm.isLocked ? 18 : 6}
        y={7}
        text={pm.pmCode}
        fontSize={11}
        fontFamily={LAYOUT.FONT_FAMILY}
        fill="#ffffff"
        fontStyle="bold"
      />

      {/* Duration label (if space) */}
      {finalWidth > 50 && pm.estimatedHours && (
        <Text
          x={finalWidth - 30}
          y={8}
          text={`${pm.estimatedHours}h`}
          fontSize={9}
          fontFamily={LAYOUT.FONT_FAMILY}
          fill="rgba(255,255,255,0.8)"
        />
      )}

      {/* Drag validation status icon */}
      {isDragging && dragValidation && (
        <Group x={finalWidth - 16} y={-8}>
          <Rect
            width={20}
            height={20}
            fill={dragValidation.isValid ? '#22c55e' : '#ef4444'}
            cornerRadius={10}
            shadowColor="#000"
            shadowBlur={4}
            shadowOpacity={0.3}
          />
          <Text
            x={4}
            y={3}
            text={dragValidation.isValid ? '✓' : '✗'}
            fontSize={12}
            fill="#ffffff"
            fontStyle="bold"
          />
        </Group>
      )}
    </Group>
  );
}

interface ConstraintWallsLayerProps {
  walls: ConstraintWall[];
  trainOrder: string[];
  days: DayData[];
  pmBlocks: PmBlock[];
  offsetX: number;
}

function ConstraintWallsLayer({ walls, trainOrder, days, pmBlocks, offsetX }: ConstraintWallsLayerProps) {
  const trainIndexMap = buildTrainIndexMap(trainOrder);
  const pmBlockMap = new Map<string, PmBlock>();
  pmBlocks.forEach((pm) => pmBlockMap.set(pm.pmId, pm));

  return (
    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
      {walls.map((wall) => {
        const pm = pmBlockMap.get(wall.pmId);
        if (!pm) return null;

        const trainIndex = trainIndexMap.get(pm.trainId);
        if (trainIndex === undefined) return null;

        const dayIndex = days.findIndex((d) => d.dateStr === wall.date);
        if (dayIndex < 0) return null;

        const x = dayIndex * LAYOUT.DAY_WIDTH;
        const y = trainIndex * LAYOUT.ROW_HEIGHT;
        const color = wall.type === 'COMPLIANCE_START'
          ? CONSTRAINT_COLORS.approaching
          : CONSTRAINT_COLORS.hardViolation;

        return (
          <Line
            key={`${wall.pmId}-${wall.type}`}
            points={[x, y + 4, x, y + LAYOUT.ROW_HEIGHT - 4]}
            stroke={color}
            strokeWidth={LAYOUT.CONSTRAINT_WALL_WIDTH}
            dash={[4, 2]}
          />
        );
      })}
    </Group>
  );
}

// =============================================================================
// Main Component
// =============================================================================

export function TacticalGanttLayer({
  data,
  trainOrder,
  fromDate,
  toDate,
  width,
  height,
  selectedPmIds,
  draggingPmId,
  dragValidation,
  onPmClick,
  onPmHover,
  onPmDragStart,
  onPmDragMove,
  onPmDragEnd,
  showConstraintWalls = true,
  showGrid = true,
}: TacticalGanttLayerProps) {
  const stageRef = useRef<StageType>(null);

  if (!data) {
    return null;
  }

  // Compute derived data inline (no useMemo - pure functions)
  const days = getDays(fromDate, toDate);
  const weeks = getWeeks(days);
  const trainIndexMap = buildTrainIndexMap(trainOrder);
  const { numbers: trainNumbers, fleets: fleetCodes } = buildTrainMetadata(data.pmBlocks);
  const selectedSet = new Set(selectedPmIds);

  const gridOffsetX = LAYOUT.TRAIN_LABEL_WIDTH;
  const contentWidth = days.length * LAYOUT.DAY_WIDTH + gridOffsetX;
  const contentHeight = trainOrder.length * LAYOUT.ROW_HEIGHT + LAYOUT.HEADER_HEIGHT;

  return (
    <Stage
      ref={stageRef}
      width={width}
      height={height}
      style={{ backgroundColor: '#f8fafc' }}
    >
      {/* Background layer */}
      <Layer>
        <Rect width={contentWidth} height={contentHeight} fill="#ffffff" />
      </Layer>

      {/* Grid layer */}
      {showGrid && (
        <Layer>
          <GanttGrid days={days} rowCount={trainOrder.length} offsetX={gridOffsetX} />
        </Layer>
      )}

      {/* Constraint walls layer */}
      {showConstraintWalls && data.constraintWalls.length > 0 && (
        <Layer>
          <ConstraintWallsLayer
            walls={data.constraintWalls}
            trainOrder={trainOrder}
            days={days}
            pmBlocks={data.pmBlocks}
            offsetX={gridOffsetX}
          />
        </Layer>
      )}

      {/* PM blocks layer */}
      <Layer>
        <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
          {data.pmBlocks.map((pm) => {
            const trainIndex = trainIndexMap.get(pm.trainId);
            if (trainIndex === undefined) return null;

            const pmDate = parseDate(pm.targetDate);
            const dayOffset = dateDiffDays(pmDate, fromDate);
            if (dayOffset < 0 || dayOffset >= days.length) return null;

            const x = dayOffset * LAYOUT.DAY_WIDTH;
            const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.PM_BLOCK_MARGIN;
            const blockWidth = pm.durationDays * LAYOUT.DAY_WIDTH - 4;

            return (
              <PmBlockRect
                key={pm.pmId}
                pm={pm}
                x={x}
                y={y}
                width={blockWidth}
                isSelected={selectedSet.has(pm.pmId)}
                isDragging={draggingPmId === pm.pmId}
                dragValidation={draggingPmId === pm.pmId ? dragValidation : null}
                onHover={onPmHover}
                onClick={onPmClick}
                onDragStart={onPmDragStart}
                onDragMove={onPmDragMove}
                onDragEnd={onPmDragEnd}
                fromDate={fromDate}
              />
            );
          })}
        </Group>
      </Layer>

      {/* Timeline header layer (on top) */}
      <Layer>
        <TimelineHeader days={days} weeks={weeks} offsetX={gridOffsetX} />
      </Layer>

      {/* Train labels layer (fixed left) */}
      <Layer>
        <TrainLabelsPanel
          trainOrder={trainOrder}
          trainNumbers={trainNumbers}
          fleetCodes={fleetCodes}
        />
      </Layer>
    </Stage>
  );
}

export default TacticalGanttLayer;

