   423→          ]}
   424→          stroke="#2563eb"
   425→          strokeWidth={2}
   426→          dash={[6, 4]}
   427→        />
   428→      )}
   429→    </Group>
   430→  );
   431→}
   432→
   433→interface PmCardProps {
   434→  pm: OperationalPmBlock;
   435→  x: number;
   436→  y: number;
   437→  width: number;
   438→  isSelected: boolean;
   439→  onHover?: (pm: OperationalPmBlock | null) => void;
   440→  onClick?: (pmId: string) => void;
   441→  onEdit?: (pmId: string) => void;
   442→  onLock?: (pmId: string) => void;
   443→}
   444→
   445→function PmCard({
   446→  pm,
   447→  x,
   448→  y,
   449→  width,
   450→  isSelected,
   451→  onHover,
   452→  onClick,
   453→}: PmCardProps) {
   454→  const statusColor = pm.displayColor || getPmStatusColor(pm.status);
   455→  const cardWidth = Math.max(width, LAYOUT.MIN_CARD_WIDTH);
   456→  const cardHeight = LAYOUT.CARD_HEIGHT;
   457→
   458→  // Calculate compliance window progress
   459→  const constraintStart = parseDate(pm.constraintStart);
   460→  const constraintEnd = parseDate(pm.constraintEnd);
   461→  const targetDate = parseDate(pm.targetDate);
   462→  const totalWindow = dateDiffDays(constraintEnd, constraintStart) || 1;
   463→  const positionInWindow = dateDiffDays(targetDate, constraintStart);
   464→  const progressPct = Math.min(100, Math.max(0, (positionInWindow / totalWindow) * 100));
   465→
   466→  // Determine compliance status
   467→  let complianceColor: string = CONSTRAINT_COLORS.ok;
   468→  if (progressPct > 90) {
   469→    complianceColor = CONSTRAINT_COLORS.hardViolation;
   470→  } else if (progressPct > 70) {
   471→    complianceColor = CONSTRAINT_COLORS.approaching;
   472→  }
   473→
   474→  return (
   475→    <Group
   476→      x={x}
   477→      y={y}
   478→      onMouseEnter={() => onHover?.(pm)}
   479→      onMouseLeave={() => onHover?.(null)}
   480→      onClick={() => onClick?.(pm.pmId)}
   481→    >
   482→      {/* Selection highlight */}
   483→      {isSelected && (
   484→        <Rect
   485→          x={-3}
   486→          y={-3}
   487→          width={cardWidth + 6}
   488→          height={cardHeight + 6}
   489→          fill="transparent"
   490→          stroke="#3b82f6"
   491→          strokeWidth={2}
   492→          cornerRadius={10}
   493→        />
   494→      )}
   495→
   496→      {/* Card background */}
   497→      <Rect
   498→        width={cardWidth}
   499→        height={cardHeight}
   500→        fill={LAYOUT.CARD_BG}
   501→        stroke={isSelected ? '#2563eb' : '#e2e8f0'}
   502→        strokeWidth={1}
   503→        cornerRadius={8}
   504→        shadowColor="#000"
   505→        shadowBlur={4}
   506→        shadowOpacity={0.08}
   507→        shadowOffsetY={2}
   508→      />
   509→
   510→      {/* Status color bar */}
   511→      <Rect
   512→        x={0}
   513→        y={0}
   514→        width={8}
   515→        height={cardHeight}
   516→        fill={statusColor}
   517→        cornerRadius={[8, 0, 0, 8]}
   518→      />
   519→
   520→      {/* Header section */}
   521→      <Group x={LAYOUT.CARD_PADDING + 4} y={LAYOUT.CARD_PADDING}>
   522→        {/* PM Code */}
   523→        <Text
   524→          text={pm.pmCode}
   525→          fontSize={14}
   526→          fontFamily={LAYOUT.FONT_FAMILY}
   527→          fill="#1e293b"
   528→          fontStyle="bold"
   529→        />
   530→
   531→        {/* Train number */}
   532→        <Text
   533→          y={18}
   534→          text={pm.trainNumber}
   535→          fontSize={11}
   536→          fontFamily={LAYOUT.FONT_FAMILY}
   537→          fill="#64748b"
   538→        />
   539→
   540→        {/* Lock indicator */}
   541→        {pm.isLocked && (
   542→          <Text
   543→            x={cardWidth - 40}
   544→            y={0}
   545→            text="🔒"
   546→            fontSize={14}
   547→          />
   548→        )}
   549→
   550→        {/* Status badge */}
   551→        <Group x={cardWidth - 90} y={0}>
   552→          <Rect
   553→            width={60}
   554→            height={20}
   555→            fill={statusColor}
   556→            cornerRadius={4}
   557→            opacity={0.2}
   558→          />
   559→          <Text
   560→            x={4}
   561→            y={4}
   562→            text={pm.status.replace('_', ' ')}
   563→            fontSize={9}
   564→            fontFamily={LAYOUT.FONT_FAMILY}
   565→            fill={statusColor}
   566→            fontStyle="bold"
   567→          />
   568→        </Group>
   569→      </Group>
   570→
   571→      {/* Date and details section */}
   572→      <Group x={LAYOUT.CARD_PADDING + 4} y={48}>
   573→        {/* Date range */}
   574→        <Text
   575→          text={formatDateRange(pm.targetDate, pm.endDate)}
   576→          fontSize={11}
   577→          fontFamily={LAYOUT.FONT_FAMILY}
   578→          fill="#475569"
   579→        />
   580→
   581→        {/* Duration */}
   582→        <Text
   583→          x={100}
   584→          text={`${pm.durationDays}d`}
   585→          fontSize={11}
   586→          fontFamily={LAYOUT.FONT_FAMILY}
   587→          fill="#64748b"
   588→        />
   589→
   590→        {/* Hours */}
   591→        {pm.estimatedHours && (
   592→          <Text
   593→            x={130}
   594→            text={`${pm.estimatedHours}h`}
   595→            fontSize={11}
   596→            fontFamily={LAYOUT.FONT_FAMILY}
   597→            fill="#64748b"
   598→          />
   599→        )}
   600→
   601→        {/* Track and depot */}
   602→        <Text
   603→          y={16}
   604→          text={[pm.depotCode, pm.trackNumber].filter(Boolean).join(' • ') || 'Unassigned'}
   605→          fontSize={10}
   606→          fontFamily={LAYOUT.FONT_FAMILY}
   607→          fill="#94a3b8"
   608→        />
   609→
   610→        {/* Shift */}
   611→        {pm.assignedShift && (
   612→          <Text
   613→            y={30}
   614→            text={`Shift: ${pm.assignedShift}`}
   615→            fontSize={10}
   616→            fontFamily={LAYOUT.FONT_FAMILY}
   617→            fill="#94a3b8"
   618→          />
   619→        )}
   620→      </Group>
   621→
   622→      {/* Compliance window visualization */}
   623→      <Group x={LAYOUT.CARD_PADDING + 4} y={100}>
   624→        <Text
   625→          text="Compliance Window"
   626→          fontSize={9}
   627→          fontFamily={LAYOUT.FONT_FAMILY}
   628→          fill="#94a3b8"
   629→        />
   630→
   631→        {/* Progress bar background */}
   632→        <Rect
   633→          y={14}
   634→          width={cardWidth - LAYOUT.CARD_PADDING * 2 - 8}
   635→          height={8}
   636→          fill="#f1f5f9"
   637→          cornerRadius={4}
   638→        />
   639→
   640→        {/* Progress bar fill */}
   641→        <Rect
   642→          y={14}
   643→          width={(cardWidth - LAYOUT.CARD_PADDING * 2 - 8) * (progressPct / 100)}
   644→          height={8}
   645→          fill={complianceColor}
   646→          cornerRadius={4}
   647→        />
   648→
   649→        {/* Target date marker */}
   650→        <Line
   651→          points={[
   652→            (cardWidth - LAYOUT.CARD_PADDING * 2 - 8) * (progressPct / 100),
   653→            12,
   654→            (cardWidth - LAYOUT.CARD_PADDING * 2 - 8) * (progressPct / 100),
   655→            24,
   656→          ]}
   657→          stroke="#1e293b"
   658→          strokeWidth={2}
   659→        />
   660→
   661→        {/* Date labels */}
   662→        <Text
   663→          y={26}
   664→          text={pm.constraintStart.slice(5)}
   665→          fontSize={8}
   666→          fontFamily={LAYOUT.FONT_FAMILY}
   667→          fill="#94a3b8"
   668→        />
   669→        <Text
   670→          x={cardWidth - LAYOUT.CARD_PADDING * 2 - 40}
   671→          y={26}
   672→          text={pm.constraintEnd.slice(5)}
   673→          fontSize={8}
   674→          fontFamily={LAYOUT.FONT_FAMILY}
   675→          fill="#94a3b8"
   676→        />
   677→      </Group>
   678→
   679→      {/* Materials section */}
   680→      <Group x={LAYOUT.CARD_PADDING + 4} y={140}>
   681→        <Text
   682→          text="Materials"
   683→          fontSize={9}
   684→          fontFamily={LAYOUT.FONT_FAMILY}
   685→          fill="#94a3b8"
   686→        />
   687→
   688→        {pm.materials.length > 0 ? (
   689→          pm.materials.slice(0, 2).map((material, idx) => (
   690→            <Group key={material.materialId} y={14 + idx * 14}>
   691→              <Text
   692→                text={getMaterialStatusIcon(material.status)}
   693→                fontSize={10}
   694→                fill={getMaterialStatusColor(material.status)}
   695→              />
   696→              <Text
   697→                x={14}
   698→                text={`${material.materialName.slice(0, 20)}${material.materialName.length > 20 ? '...' : ''}`}
   699→                fontSize={9}
   700→                fontFamily={LAYOUT.FONT_FAMILY}
   701→                fill="#64748b"
   702→              />
   703→              <Text
   704→                x={cardWidth - 60}
   705→                text={`${material.quantityAvailable}/${material.quantityRequired}`}
   706→                fontSize={9}
   707→                fontFamily={LAYOUT.FONT_FAMILY}
   708→                fill={getMaterialStatusColor(material.status)}
   709→              />
   710→            </Group>
   711→          ))
   712→        ) : (
   713→          <Text
   714→            y={14}
   715→            text="No materials required"
   716→            fontSize={9}
   717→            fontFamily={LAYOUT.FONT_FAMILY}
   718→            fill="#94a3b8"
   719→            fontStyle="italic"
   720→          />
   721→        )}
   722→      </Group>
   723→    </Group>
   724→  );
   725→}
   726→
   727→// =============================================================================
   728→// Main Component
   729→// =============================================================================
   730→
   731→export function OperationalDetailLayer({
   732→  data,
   733→  fromDate,
   734→  toDate,
   735→  width,
   736→  height,
   737→  selectedPmIds = [],
   738→  onPmClick,
   739→  onPmHover,
   740→  showGrid = true,
   741→}: OperationalDetailLayerProps) {
   742→  const stageRef = useRef<StageType>(null);
   743→
   744→  if (!data) {
   745→    return null;
   746→  }
   747→
   748→  // Compute derived data
   749→  const days = getDays(fromDate, toDate);
   750→  const weeks = getWeeks(days);
   751→  const trainGroups = buildTrainGroups(data.pmBlocks);
   752→  const trainOrder = Array.from(trainGroups.keys());
   753→  const selectedSet = new Set(selectedPmIds);
   754→
   755→  const gridOffsetX = LAYOUT.TRAIN_LABEL_WIDTH;
   756→  const contentWidth = days.length * LAYOUT.DAY_WIDTH + gridOffsetX;
   757→  const contentHeight = trainOrder.length * LAYOUT.ROW_HEIGHT + LAYOUT.HEADER_HEIGHT;
   758→
   759→  return (
   760→    <Stage
   761→      ref={stageRef}
   762→      width={width}
   763→      height={height}
   764→      style={{ backgroundColor: '#f8fafc' }}
   765→    >
   766→      {/* Background layer */}
   767→      <Layer>
   768→        <Rect width={contentWidth} height={contentHeight} fill="#ffffff" />
   769→      </Layer>
   770→
   771→      {/* Grid layer */}
   772→      {showGrid && (
   773→        <Layer>
   774→          <GridLayer days={days} rowCount={trainOrder.length} offsetX={gridOffsetX} />
   775→        </Layer>
   776→      )}
   777→
   778→      {/* PM Cards layer */}
   779→      <Layer>
   780→        <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
   781→          {trainOrder.map((trainId, trainIndex) => {
   782→            const pms = trainGroups.get(trainId) || [];
   783→
   784→            return pms.map((pm) => {
   785→              const pmDate = parseDate(pm.targetDate);
   786→              const dayOffset = dateDiffDays(pmDate, fromDate);
   787→              if (dayOffset < 0 || dayOffset >= days.length) return null;
   788→
   789→              const x = dayOffset * LAYOUT.DAY_WIDTH + LAYOUT.CARD_MARGIN;
   790→              const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.CARD_MARGIN;
   791→              const cardWidth = pm.durationDays * LAYOUT.DAY_WIDTH - LAYOUT.CARD_MARGIN * 2;
   792→
   793→              return (
   794→                <PmCard
   795→                  key={pm.pmId}
   796→                  pm={pm}
   797→                  x={x}
   798→                  y={y}
   799→                  width={cardWidth}
   800→                  isSelected={selectedSet.has(pm.pmId)}
   801→                  onHover={onPmHover}
   802→                  onClick={onPmClick}
   803→                />
   804→              );
   805→            });
   806→          })}
   807→        </Group>
   808→      </Layer>
   809→
   810→      {/* Timeline header layer (on top) */}
   811→      <Layer>
   812→        <TimelineHeader days={days} weeks={weeks} offsetX={gridOffsetX} />
   813→      </Layer>
   814→
   815→      {/* Train labels layer (fixed left) */}
   816→      <Layer>
   817→        <TrainLabelsPanel trainGroups={trainGroups} trainOrder={trainOrder} />
   818→      </Layer>
   819→    </Stage>
   820→  );
   821→}
   822→
   823→export default OperationalDetailLayer;
   824→

