     1→/**
     2→ * Detail Card Overlay
     3→ *
     4→ * React DOM overlay for the detail view (zoom levels 16+).
     5→ * Provides rich PM editing interfaces with:
     6→ * - Full PM details in expandable cards
     7→ * - Inline editing (date, depot, track, shift)
     8→ * - Crew assignment display
     9→ * - Material status with availability badges
    10→ * - Compliance window timeline visualization
    11→ * - Change history panel
    12→ * - Real-time constraint validation feedback
    13→ *
    14→ * Uses BlueprintJS components for consistent UI.
    15→ * State managed via @belt/tools (no React hooks).
    16→ *
    17→ * @see specs/006-user-interface.md Section 6.3.4, 6.3.5
    18→ */
    19→
    20→import { useRef } from 'react';
    21→import {
    22→  Card,
    23→  Elevation,
    24→  Tag,
    25→  Intent,
    26→  Button,
    27→  ButtonGroup,
    28→  Collapse,
    29→  Icon,
    30→  ProgressBar,
    31→  Divider,
    32→  HTMLTable,
    33→  Tooltip,
    34→  Position,
    35→  Popover,
    36→  Menu,
    37→  MenuItem,
    38→  MenuDivider,
    39→} from '@blueprintjs/core';
    40→
    41→import type { OperationalPmBlock, OperationalCanvasData, MaterialStatus } from './types';
    42→import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';
    43→
    44→// =============================================================================
    45→// Types
    46→// =============================================================================
    47→
    48→export interface DetailPmBlock extends OperationalPmBlock {
    49→  /** Change history for audit trail */
    50→  changeHistory?: ChangeHistoryEntry[];
    51→  /** Constraint validation results */
    52→  constraintValidation?: DetailConstraintValidation;
    53→  /** Assigned crew (if available) */
    54→  assignedCrew?: CrewAssignment[];
    55→}
    56→
    57→export interface ChangeHistoryEntry {
    58→  id: string;
    59→  timestamp: string;
    60→  changeType: 'CREATE' | 'MOVE' | 'REASSIGN' | 'LOCK' | 'UNLOCK' | 'STATUS_CHANGE';
    61→  field?: string;
    62→  oldValue?: string;
    63→  newValue?: string;
    64→  userId: string;
    65→  userName: string;
    66→  reason?: string;
    67→}
    68→
    69→export interface DetailConstraintValidation {
    70→  isValid: boolean;
    71→  violations: DetailConstraintViolation[];
    72→  warnings: DetailConstraintWarning[];
    73→}
    74→
    75→export interface DetailConstraintViolation {
    76→  type: 'HARD' | 'SOFT';
    77→  constraint: string;
    78→  message: string;
    79→  canOverride: boolean;
    80→}
    81→
    82→export interface DetailConstraintWarning {
    83→  type: string;
    84→  message: string;
    85→}
    86→
    87→export interface CrewAssignment {
    88→  crewId: string;
    89→  crewName: string;
    90→  role: string;
    91→  shift: string;
    92→}
    93→
    94→export interface DetailCanvasData extends OperationalCanvasData {
    95→  pmBlocks: DetailPmBlock[];
    96→}
    97→
    98→export interface DetailCardOverlayProps {
    99→  data: DetailCanvasData | null;
   100→  fromDate: Date;
   101→  toDate: Date;
   102→  width: number;
   103→  height: number;
   104→  selectedPmIds?: string[];
   105→  expandedPmIds?: string[];
   106→  onPmSelect?: (pmId: string) => void;
   107→  onPmExpand?: (pmId: string) => void;
   108→  onPmCollapse?: (pmId: string) => void;
   109→  onPmEdit?: (pmId: string, field: string, value: unknown) => void;
   110→  onPmLock?: (pmId: string) => void;
   111→  onPmUnlock?: (pmId: string) => void;
   112→  onPmMove?: (pmId: string, newDate: string) => void;
   113→  onViewHistory?: (pmId: string) => void;
   114→  showGrid?: boolean;
   115→}
   116→
   117→// =============================================================================
   118→// Constants
   119→// =============================================================================
   120→
   121→const LAYOUT = {
   122→  HEADER_HEIGHT: 80,
   123→  TRAIN_LABEL_WIDTH: 160,
   124→  CARD_WIDTH: 360,
   125→  CARD_EXPANDED_WIDTH: 480,
   126→  CARD_HEIGHT: 200,
   127→  CARD_EXPANDED_HEIGHT: 500,
   128→  CARD_MARGIN: 16,
   129→  DAY_WIDTH: 120,
   130→  ROW_HEIGHT: 220,
   131→  EXPANDED_ROW_HEIGHT: 520,
   132→  GRID_LINE_COLOR: '#e2e8f0',
   133→  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
   134→};
   135→
   136→const PM_STATUS_INTENT: Record<string, Intent> = {
   137→  SCHEDULED: Intent.PRIMARY,
   138→  IN_PROGRESS: Intent.WARNING,
   139→  COMPLETED: Intent.SUCCESS,
   140→  CANCELLED: Intent.NONE,
   141→  DEFERRED: Intent.NONE,
   142→  OVERDUE: Intent.DANGER,
   143→};
   144→
   145→// =============================================================================
   146→// Utility Functions
   147→// =============================================================================
   148→
   149→function getPmStatusColor(status: string): string {
   150→  const normalizedStatus = status.toLowerCase().replace('_', '') as keyof typeof PM_STATUS_COLORS;
   151→  return PM_STATUS_COLORS[normalizedStatus] ?? PM_STATUS_COLORS.scheduled;
   152→}
   153→
   154→function getPmStatusIntent(status: string): Intent {
   155→  return PM_STATUS_INTENT[status] ?? Intent.NONE;
   156→}
   157→
   158→function getMaterialStatusIcon(status: MaterialStatus): string {
   159→  switch (status) {
   160→    case 'AVAILABLE':
   161→      return 'tick-circle';
   162→    case 'LOW_STOCK':
   163→      return 'warning-sign';
   164→    case 'UNAVAILABLE':
   165→      return 'error';
   166→    case 'ARRIVING':
   167→      return 'time';
   168→    default:
   169→      return 'help';
   170→  }
   171→}
   172→
   173→function getMaterialStatusIntent(status: MaterialStatus): Intent {
   174→  switch (status) {
   175→    case 'AVAILABLE':
   176→      return Intent.SUCCESS;
   177→    case 'LOW_STOCK':
   178→      return Intent.WARNING;
   179→    case 'UNAVAILABLE':
   180→      return Intent.DANGER;
   181→    case 'ARRIVING':
   182→      return Intent.PRIMARY;
   183→    default:
   184→      return Intent.NONE;
   185→  }
   186→}
   187→
   188→function formatDate(dateStr: string): string {
   189→  const date = new Date(dateStr);
   190→  return date.toLocaleDateString('en-US', {
   191→    weekday: 'short',
   192→    month: 'short',
   193→    day: 'numeric',
   194→    year: 'numeric',
   195→  });
   196→}
   197→
   198→function formatDateTime(dateStr: string): string {
   199→  const date = new Date(dateStr);
   200→  return date.toLocaleDateString('en-US', {
   201→    month: 'short',
   202→    day: 'numeric',
   203→    hour: '2-digit',
   204→    minute: '2-digit',
   205→  });
   206→}
   207→
   208→function getDays(fromDate: Date, toDate: Date): Date[] {
   209→  const days: Date[] = [];
   210→  const current = new Date(fromDate);
   211→  while (current <= toDate) {
   212→    days.push(new Date(current));
   213→    current.setDate(current.getDate() + 1);
   214→  }
   215→  return days;
   216→}
   217→
   218→function dateDiffDays(a: Date, b: Date): number {
   219→  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
   220→}
   221→
   222→function parseDate(dateStr: string): Date {
   223→  return new Date(dateStr + 'T00:00:00');
   224→}
   225→
   226→function buildTrainGroups(pmBlocks: DetailPmBlock[]): Map<string, DetailPmBlock[]> {
   227→  const groups = new Map<string, DetailPmBlock[]>();
   228→  for (const pm of pmBlocks) {
   229→    if (!groups.has(pm.trainId)) {
   230→      groups.set(pm.trainId, []);
   231→    }
   232→    groups.get(pm.trainId)!.push(pm);
   233→  }
   234→  return groups;
   235→}
   236→
   237→function calculateComplianceProgress(pm: DetailPmBlock): {
   238→  progress: number;
   239→  daysRemaining: number;
   240→  status: 'ok' | 'approaching' | 'violation';
   241→} {
   242→  const constraintStart = parseDate(pm.constraintStart);
   243→  const constraintEnd = parseDate(pm.constraintEnd);
   244→  const targetDate = parseDate(pm.targetDate);
   245→  const today = new Date();
   246→  today.setHours(0, 0, 0, 0);
   247→
   248→  const totalWindow = dateDiffDays(constraintEnd, constraintStart) || 1;
   249→  const positionInWindow = dateDiffDays(targetDate, constraintStart);
   250→  const daysRemaining = dateDiffDays(constraintEnd, today);
   251→  const progress = Math.min(100, Math.max(0, (positionInWindow / totalWindow) * 100));
   252→
   253→  let status: 'ok' | 'approaching' | 'violation' = 'ok';
   254→  if (progress > 90 || daysRemaining < 0) {
   255→    status = 'violation';
   256→  } else if (progress > 70 || daysRemaining < 7) {
   257→    status = 'approaching';
   258→  }
   259→
   260→  return { progress, daysRemaining, status };
   261→}
   262→
   263→// =============================================================================
   264→// Sub-Components
   265→// =============================================================================
   266→
   267→interface ComplianceTimelineProps {
   268→  pm: DetailPmBlock;
   269→}
   270→
   271→function ComplianceTimeline({ pm }: ComplianceTimelineProps) {
   272→  const { progress, daysRemaining, status } = calculateComplianceProgress(pm);
   273→
   274→  let progressIntent: Intent = Intent.SUCCESS;
   275→  let statusColor: string = CONSTRAINT_COLORS.ok;
   276→  if (status === 'violation') {
   277→    progressIntent = Intent.DANGER;
   278→    statusColor = CONSTRAINT_COLORS.hardViolation;
   279→  } else if (status === 'approaching') {
   280→    progressIntent = Intent.WARNING;
   281→    statusColor = CONSTRAINT_COLORS.approaching;
   282→  }
   283→
   284→  return (
   285→    <div style={{ marginTop: 12 }}>
   286→      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
   287→        <span style={{ fontSize: 11, color: '#64748b' }}>Compliance Window</span>
   288→        <span style={{ fontSize: 11, color: statusColor, fontWeight: 500 }}>
   289→          {daysRemaining > 0 ? `${daysRemaining} days remaining` : 'Past deadline'}
   290→        </span>
   291→      </div>
   292→      <ProgressBar
   293→        value={progress / 100}
   294→        intent={progressIntent}
   295→        animate={false}
   296→        stripes={false}
   297→      />
   298→      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 4 }}>
   299→        <span style={{ fontSize: 10, color: '#94a3b8' }}>
   300→          {formatDate(pm.constraintStart)}
   301→        </span>
   302→        <span style={{ fontSize: 10, color: '#1e293b', fontWeight: 500 }}>
   303→          Scheduled: {formatDate(pm.targetDate)}
   304→        </span>
   305→        <span style={{ fontSize: 10, color: '#94a3b8' }}>
   306→          {formatDate(pm.constraintEnd)}
   307→        </span>
   308→      </div>
   309→    </div>
   310→  );
   311→}
   312→
   313→interface MaterialsSectionProps {
   314→  materials: DetailPmBlock['materials'];
   315→}
   316→
   317→function MaterialsSection({ materials }: MaterialsSectionProps) {
   318→  if (materials.length === 0) {
   319→    return (
   320→      <div style={{ padding: '12px 0', color: '#94a3b8', fontStyle: 'italic', fontSize: 12 }}>
   321→        No materials required for this PM
   322→      </div>
   323→    );
   324→  }
   325→
   326→  return (
   327→    <HTMLTable compact style={{ width: '100%', fontSize: 12 }}>
   328→      <thead>
   329→        <tr>
   330→          <th>Material</th>
   331→          <th style={{ textAlign: 'center' }}>Required</th>
   332→          <th style={{ textAlign: 'center' }}>Available</th>
   333→          <th style={{ textAlign: 'center' }}>Status</th>
   334→        </tr>
   335→      </thead>
   336→      <tbody>
   337→        {materials.map((material) => (
   338→          <tr key={material.materialId}>
   339→            <td>
   340→              <Tooltip content={material.materialId} position={Position.TOP}>
   341→                <span>{material.materialName}</span>
   342→              </Tooltip>
   343→            </td>
   344→            <td style={{ textAlign: 'center' }}>{material.quantityRequired}</td>
   345→            <td style={{ textAlign: 'center' }}>{material.quantityAvailable}</td>
   346→            <td style={{ textAlign: 'center' }}>
   347→              <Tag
   348→                minimal
   349→                icon={getMaterialStatusIcon(material.status) as 'tick-circle' | 'warning-sign' | 'error' | 'time' | 'help'}
   350→                intent={getMaterialStatusIntent(material.status)}
   351→              >
   352→                {material.status.replace('_', ' ')}
   353→              </Tag>
   354→            </td>
   355→          </tr>
   356→        ))}
   357→      </tbody>
   358→    </HTMLTable>
   359→  );
   360→}
   361→
   362→interface ChangeHistorySectionProps {
   363→  history?: ChangeHistoryEntry[];
   364→}
   365→
   366→function ChangeHistorySection({ history }: ChangeHistorySectionProps) {
   367→  if (!history || history.length === 0) {
   368→    return (
   369→      <div style={{ padding: '12px 0', color: '#94a3b8', fontStyle: 'italic', fontSize: 12 }}>
   370→        No change history available
   371→      </div>
   372→    );
   373→  }
   374→
   375→  const getChangeIcon = (type: ChangeHistoryEntry['changeType']) => {
   376→    switch (type) {
   377→      case 'CREATE':
   378→        return 'add';
   379→      case 'MOVE':
   380→        return 'move';
   381→      case 'REASSIGN':
   382→        return 'swap-horizontal';
   383→      case 'LOCK':
   384→        return 'lock';
   385→      case 'UNLOCK':
   386→        return 'unlock';
   387→      case 'STATUS_CHANGE':
   388→        return 'refresh';
   389→      default:
   390→        return 'history';
   391→    }
   392→  };
   393→
   394→  return (
   395→    <div style={{ maxHeight: 200, overflowY: 'auto' }}>
   396→      {history.slice(0, 10).map((entry) => (
   397→        <div
   398→          key={entry.id}
   399→          style={{
   400→            display: 'flex',
   401→            alignItems: 'flex-start',
   402→            padding: '8px 0',
   403→            borderBottom: '1px solid #f1f5f9',
   404→          }}
   405→        >
   406→          <Icon
   407→            icon={getChangeIcon(entry.changeType) as 'add' | 'move' | 'swap-horizontal' | 'lock' | 'unlock' | 'refresh' | 'history'}
   408→            size={14}
   409→            style={{ marginRight: 8, marginTop: 2, color: '#64748b' }}
   410→          />
   411→          <div style={{ flex: 1 }}>
   412→            <div style={{ fontSize: 12, color: '#1e293b' }}>
   413→              <strong>{entry.changeType.replace('_', ' ')}</strong>
   414→              {entry.field && ` - ${entry.field}`}
   415→            </div>
   416→            {entry.oldValue && entry.newValue && (
   417→              <div style={{ fontSize: 11, color: '#64748b' }}>
   418→                {entry.oldValue} → {entry.newValue}
   419→              </div>
