   421→            <div style={{ fontSize: 10, color: '#94a3b8' }}>
   422→              {formatDateTime(entry.timestamp)} by {entry.userName}
   423→            </div>
   424→          </div>
   425→        </div>
   426→      ))}
   427→    </div>
   428→  );
   429→}
