   523→
   524→function DetailCard({
   525→  pm,
   526→  isSelected,
   527→  isExpanded,
   528→  onSelect,
   529→  onExpand,
   530→  onCollapse,
   531→  onEdit,
   532→  onLock,
   533→  onUnlock,
   534→  onViewHistory,
   535→}: DetailCardProps) {
   536→  const statusColor = pm.displayColor || getPmStatusColor(pm.status);
   537→  const fleetColor = FLEET_COLORS[pm.fleetCode as keyof typeof FLEET_COLORS] || FLEET_COLORS.KS;
   538→  const historyRef = useRef<HTMLDivElement>(null);
   539→  const materialsRef = useRef<HTMLDivElement>(null);
   540→  const constraintsRef = useRef<HTMLDivElement>(null);
   541→
   542→  const cardWidth = isExpanded ? LAYOUT.CARD_EXPANDED_WIDTH : LAYOUT.CARD_WIDTH;
