   107→}
   108→
   109→/**
   110→ * Client-side quick validation for immediate feedback.
   111→ * Checks basic constraints without API call.
   112→ */
   113→export function quickValidatePmMove(
   114→  params: ValidatePmMoveParams & {
   115→    constraintStart: string;
   116→    constraintEnd: string;
   117→    isLocked: boolean;
   118→  }
   119→): DragValidationState {
   120→  const violations: DragConstraintViolation[] = [];
   121→
   122→  // Check if PM is locked
   123→  if (params.isLocked) {
   124→    violations.push({
   125→      type: 'MAXIMO_LOCK',
   126→      severity: 'ERROR',
   127→      message: 'Cannot move: PM is locked',
   128→    });
   129→  }
   130→
   131→  // Check compliance window
   132→  const targetDate = new Date(params.targetDate);
   133→  const windowStart = new Date(params.constraintStart);
   134→  const windowEnd = new Date(params.constraintEnd);
   135→
   136→  if (targetDate < windowStart) {
   137→    violations.push({
   138→      type: 'COMPLIANCE_WINDOW',
   139→      severity: 'ERROR',
   140→      message: `Target date ${params.targetDate} is before compliance window start (${params.constraintStart})`,
   141→    });
   142→  }
   143→
   144→  if (targetDate > windowEnd) {
   145→    violations.push({
   146→      type: 'COMPLIANCE_WINDOW',
   147→      severity: 'ERROR',
   148→      message: `Target date ${params.targetDate} is after compliance window end (${params.constraintEnd})`,
   149→    });
   150→  }
   151→
   152→  // Check if same date (no change)
   153→  if (params.currentDate === params.targetDate) {
   154→    return {
   155→      isValid: true,
   156→      message: null,
   157→      violations: [],
   158→    };
   159→  }
   160→
   161→  const hasErrors = violations.some(v => v.severity === 'ERROR');
   162→
   163→  return {
   164→    isValid: !hasErrors,
   165→    message: violations.length > 0
   166→      ? violations.map(v => v.message).join('; ')
   167→      : null,
   168→    violations,
   169→  };
   170→}
   171→
   172→// =============================================================================
   173→// Debounced Validation
   174→// =============================================================================
   175→
   176→interface DebouncedValidation {
   177→  validate: (params: ValidatePmMoveParams) => void;
   178→  cancel: () => void;
   179→}
   180→
   181→/**
   182→ * Creates a debounced validation function for real-time drag feedback.
   183→ * Cancels previous pending validation when a new position is provided.
   184→ */
   185→export function createDebouncedValidation(
   186→  onResult: (result: DragValidationState) => void,
   187→  options: { delay?: number; baseUrl?: string } = {}
   188→): DebouncedValidation {
   189→  const { delay = 150, baseUrl = '/api/v1' } = options;
   190→
   191→  let timeoutId: NodeJS.Timeout | null = null;
   192→  let abortController: AbortController | null = null;
   193→
   194→  const validate = (params: ValidatePmMoveParams) => {
   195→    // Cancel previous
   196→    if (timeoutId) {
   197→      clearTimeout(timeoutId);
   198→    }
   199→    if (abortController) {
   200→      abortController.abort();
   201→    }
   202→
   203→    // Create new abort controller
