   209→      const result = await validatePmMove(params, { baseUrl, signal });
   210→      if (!signal.aborted) {
   211→        onResult(result);
   212→      }
   213→    }, delay);
   214→  };
   215→
   216→  const cancel = () => {
   217→    if (timeoutId) {
   218→      clearTimeout(timeoutId);
   219→      timeoutId = null;
   220→    }
   221→    if (abortController) {
   222→      abortController.abort();
   223→      abortController = null;
   224→    }
   225→  };
   226→
   227→  return { validate, cancel };
   228→}
   229→
   230→// =============================================================================
   231→// Impact Assessment
   232→// =============================================================================
   233→
   234→/**
   235→ * Fetches detailed impact assessment for a PM move.
