   257→      return null;
   258→    }
   259→
   260→    const data = await response.json() as { data: PmMoveImpact };
   261→    return data.data;
   262→  } catch {
   263→    return null;
   264→  }
   265→}
   266→
   267→/**
   268→ * Commits a PM move to the server.
   269→ * Returns true on success, throws on failure.
   270→ */
   271→export async function commitPmMove(
   272→  params: ValidatePmMoveParams & { reason?: string },
   273→  options: { baseUrl?: string } = {}
   274→): Promise<{ success: boolean; explanation?: string }> {
   275→  const { baseUrl = '/api/v1' } = options;
   276→
   277→  const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}`, {
   278→    method: 'PATCH',
   279→    headers: {
   280→      'Content-Type': 'application/json',
   281→    },
   282→    body: JSON.stringify({
   283→      targetDate: params.targetDate,
   284→      reason: params.reason || 'Manual reschedule via canvas drag-and-drop',
   285→    }),
   286→  });
   287→
   288→  if (!response.ok) {
   289→    const error = await response.json() as { error?: { message?: string } };
   290→    throw new Error(error.error?.message || 'Failed to reschedule PM');
   291→  }
   292→
   293→  const data = await response.json() as {
   294→    data: { explanation?: { changeType: string; impactAssessment: string } };
   295→  };
   296→
   297→  return {
   298→    success: true,
   299→    explanation: data.data.explanation?.impactAssessment,
   300→  };
   301→}
