/**
 * UI Slice
 *
 * State management for global UI state: toasts, modals, loading, errors.
 *
 * @see specs/006-user-interface.md Section 6.8
 */

import { createSlice } from '@belt/tools';
import type { Toast, ModalState, LoadingState, ErrorState, OptimizerJob } from '../types';

// =============================================================================
// UI Slice State
// =============================================================================

export interface UiSliceState {
  // Toast notifications
  toasts: Toast[];
  maxToasts: number;

  // Modal state
  modal: ModalState;

  // Loading indicators
  loading: LoadingState;

  // Global error state
  error: ErrorState;

  // Sidebar collapsed
  sidebarCollapsed: boolean;

  // Help panel open
  helpPanelOpen: boolean;

  // Keyboard shortcuts enabled
  shortcutsEnabled: boolean;

  // Theme
  theme: 'light' | 'dark' | 'system';

  // Optimizer jobs tracking
  optimizerJobs: OptimizerJob[];
  activeJobId: string | null;

  // Connection status
  isOnline: boolean;
  websocketConnected: boolean;

  // Sync status
  lastSyncAt: number | null;
  syncInProgress: boolean;

  // Index signature for MachineState compatibility
  [key: string]: unknown;
}

const initialUiState: UiSliceState = {
  toasts: [],
  maxToasts: 5,
  modal: {
    isOpen: false,
    type: null,
    data: null,
  },
  loading: {
    trains: false,
    pmSchedule: false,
    canvas: false,
    optimizer: false,
  },
  error: {
    message: null,
    code: null,
    details: null,
    timestamp: null,
  },
  sidebarCollapsed: false,
  helpPanelOpen: false,
  shortcutsEnabled: true,
  theme: 'system',
  optimizerJobs: [],
  activeJobId: null,
  isOnline: true,
  websocketConnected: false,
  lastSyncAt: null,
  syncInProgress: false,
};

let toastIdCounter = 0;

export const uiSlice = createSlice({
  id: 'ui',
  initial: initialUiState,
  cache: { policy: 'session' },
  reducers: {
    // ==========================================================================
    // Toast Notifications
    // ==========================================================================

    addToast: (
      s,
      toast: Omit<Toast, 'id' | 'createdAt'> & { id?: string }
    ) => {
      const state = s as UiSliceState;
      const newToast: Toast = {
        id: toast.id ?? `toast-${++toastIdCounter}`,
        type: toast.type,
        title: toast.title,
        message: toast.message,
        duration: toast.duration ?? 5000,
        dismissible: toast.dismissible ?? true,
        createdAt: Date.now(),
      };

      state.toasts.push(newToast);

      // Trim to max toasts
      if (state.toasts.length > state.maxToasts) {
        state.toasts.shift();
      }
    },

    removeToast: (s, toastId: string) => {
      const state = s as UiSliceState;
      state.toasts = state.toasts.filter((t) => t.id !== toastId);
    },

    clearToasts: (s) => {
      const state = s as UiSliceState;
      state.toasts = [];
    },

    // Convenience toast creators
    showSuccess: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'success',
        title: payload.title,
        message: payload.message,
        duration: 3000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showError: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'error',
        title: payload.title,
        message: payload.message,
        duration: 8000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showWarning: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'warning',
        title: payload.title,
        message: payload.message,
        duration: 6000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showInfo: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'info',
        title: payload.title,
        message: payload.message,
        duration: 5000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    // ==========================================================================
    // Modal
    // ==========================================================================

    openModal: (s, payload: { type: string; data?: Record<string, unknown> }) => {
      const state = s as UiSliceState;
      state.modal = {
        isOpen: true,
        type: payload.type,
        data: payload.data ?? null,
      };
    },

    closeModal: (s) => {
      const state = s as UiSliceState;
      state.modal = {
        isOpen: false,
        type: null,
        data: null,
      };
    },

    updateModalData: (s, data: Record<string, unknown>) => {
      const state = s as UiSliceState;
      if (state.modal.isOpen) {
        state.modal.data = { ...state.modal.data, ...data };
      }
    },

    // ==========================================================================
    // Loading
    // ==========================================================================

    setLoading: (s, payload: Partial<LoadingState>) => {
      const state = s as UiSliceState;
      state.loading = { ...state.loading, ...payload };
    },

    startLoading: (s, key: keyof LoadingState) => {
      const state = s as UiSliceState;
      state.loading[key] = true;
    },

    stopLoading: (s, key: keyof LoadingState) => {
      const state = s as UiSliceState;
      state.loading[key] = false;
    },

    clearLoading: (s) => {
      const state = s as UiSliceState;
      state.loading = {
        trains: false,
        pmSchedule: false,
        canvas: false,
        optimizer: false,
      };
    },

    // ==========================================================================
    // Error
    // ==========================================================================

    setError: (
      s,
      payload: { message: string; code?: string; details?: Record<string, unknown> }
    ) => {
      const state = s as UiSliceState;
      state.error = {
        message: payload.message,
        code: payload.code ?? null,
        details: payload.details ?? null,
        timestamp: Date.now(),
      };
    },

    clearError: (s) => {
      const state = s as UiSliceState;
      state.error = {
        message: null,
        code: null,
        details: null,
        timestamp: null,
      };
    },

    // ==========================================================================
    // Layout
    // ==========================================================================

    toggleSidebar: (s) => {
      const state = s as UiSliceState;
      state.sidebarCollapsed = !state.sidebarCollapsed;
    },

    setSidebarCollapsed: (s, collapsed: boolean) => {
      const state = s as UiSliceState;
      state.sidebarCollapsed = collapsed;
    },

    toggleHelpPanel: (s) => {
      const state = s as UiSliceState;
      state.helpPanelOpen = !state.helpPanelOpen;
    },

    setHelpPanelOpen: (s, open: boolean) => {
      const state = s as UiSliceState;
      state.helpPanelOpen = open;
    },

    // ==========================================================================
    // Preferences
    // ==========================================================================

    setShortcutsEnabled: (s, enabled: boolean) => {
      const state = s as UiSliceState;
      state.shortcutsEnabled = enabled;
    },

    setTheme: (s, theme: 'light' | 'dark' | 'system') => {
      const state = s as UiSliceState;
      state.theme = theme;
    },

    // ==========================================================================
    // Optimizer Jobs
    // ==========================================================================

    addOptimizerJob: (s, job: OptimizerJob) => {
      const state = s as UiSliceState;
      state.optimizerJobs.push(job);
      state.activeJobId = job.id;
    },

    updateOptimizerJob: (s, job: Partial<OptimizerJob> & { id: string }) => {
      const state = s as UiSliceState;
      const index = state.optimizerJobs.findIndex((j) => j.id === job.id);
      if (index !== -1) {
        state.optimizerJobs[index] = { ...state.optimizerJobs[index], ...job };
      }
    },

    removeOptimizerJob: (s, jobId: string) => {
      const state = s as UiSliceState;
      state.optimizerJobs = state.optimizerJobs.filter((j) => j.id !== jobId);
      if (state.activeJobId === jobId) {
        state.activeJobId = state.optimizerJobs[0]?.id ?? null;
      }
    },

    setActiveJob: (s, jobId: string | null) => {
      const state = s as UiSliceState;
      state.activeJobId = jobId;
    },

    clearCompletedJobs: (s) => {
      const state = s as UiSliceState;
      state.optimizerJobs = state.optimizerJobs.filter(
        (j) => j.status !== 'COMPLETED' && j.status !== 'FAILED'
      );
    },

    // ==========================================================================
    // Connection Status
    // ==========================================================================

    setOnlineStatus: (s, isOnline: boolean) => {
      const state = s as UiSliceState;
      state.isOnline = isOnline;
    },

    setWebsocketConnected: (s, connected: boolean) => {
      const state = s as UiSliceState;
      state.websocketConnected = connected;
    },

    // ==========================================================================
    // Sync Status
    // ==========================================================================

    startSync: (s) => {
      const state = s as UiSliceState;
      state.syncInProgress = true;
    },

    finishSync: (s) => {
      const state = s as UiSliceState;
      state.syncInProgress = false;
      state.lastSyncAt = Date.now();
    },

    // ==========================================================================
    // Reset
    // ==========================================================================

    reset: (s) => {
      const state = s as UiSliceState;
      Object.assign(state, initialUiState);
    },
  },
});

// =============================================================================
// Selectors
// =============================================================================

/** Check if any loading is in progress */
export function isAnyLoading(state: UiSliceState): boolean {
  return Object.values(state.loading).some(Boolean);
}

/** Get active optimizer job */
export function selectActiveJob(state: UiSliceState): OptimizerJob | undefined {
  return state.activeJobId
    ? state.optimizerJobs.find((j) => j.id === state.activeJobId)
    : undefined;
}

/** Get running optimizer jobs */
export function selectRunningJobs(state: UiSliceState): OptimizerJob[] {
  return state.optimizerJobs.filter((j) => j.status === 'RUNNING' || j.status === 'PENDING');
}

/** Check if there's an error */
export function hasError(state: UiSliceState): boolean {
  return state.error.message !== null;
}

/** Get visible toasts */
export function selectVisibleToasts(state: UiSliceState): Toast[] {
  const now = Date.now();
  return state.toasts.filter((t) => now - t.createdAt < t.duration);
}

/** Check connection status */
export function isFullyConnected(state: UiSliceState): boolean {
  return state.isOnline && state.websocketConnected;
}

