     1→     1→/**
     2→     2→ * Strategic Heatmap Layer
     3→     3→ *
     4→     4→ * deck.gl WebGL layer for the 12-year strategic PM density view.
     5→     5→ * Renders a heatmap grid where:
     6→     6→ * - Rows = trains
     7→     7→ * - Columns = years
     8→     8→ * - Cell color = PM density (intensity)
     9→     9→ *
    10→    10→ * Used at zoom levels 0-8 (STRATEGIC and TACTICAL_WIDE).
    11→    11→ *
    12→    12→ * @see specs/006-user-interface.md Section 6.3.2
    13→    13→ */
    14→    14→
    15→    15→import { ScatterplotLayer, TextLayer } from '@deck.gl/layers';
    16→    16→import DeckGL from '@deck.gl/react';
    17→    17→import { OrthographicView } from '@deck.gl/core';
    18→    18→
    19→    19→import type { StrategicCanvasData, HeatmapCell } from './types';
    20→    20→
    21→    21→// =============================================================================
    22→    22→// Constants
    23→    23→// =============================================================================
    24→    24→
    25→    25→const CELL_WIDTH = 80;
    26→    26→const CELL_HEIGHT = 30;
    27→    27→const CELL_PADDING = 4;
    28→    28→const LABEL_WIDTH = 100;
    29→    29→const HEADER_HEIGHT = 40;
    30→    30→
    31→    31→/** PM density color scale (light to dark blue) */
    32→    32→const PM_DENSITY_COLORS: [number, number, number, number][] = [
    33→    33→  [240, 249, 255, 255], // 0 PMs - very light blue
    34→    34→  [186, 230, 253, 255], // 1 PM - light blue
    35→    35→  [125, 211, 252, 255], // 2 PMs
    36→    36→  [56, 189, 248, 255],  // 3 PMs
    37→    37→  [14, 165, 233, 255],  // 4 PMs
    38→    38→  [2, 132, 199, 255],   // 5 PMs
    39→    39→  [3, 105, 161, 255],   // 6 PMs
    40→    40→  [7, 89, 133, 255],    // 7+ PMs - dark blue
    41→    41→];
    42→    42→
    43→    43→/** Fleet colors */
    44→    44→const FLEET_COLORS: Record<string, [number, number, number, number]> = {
    45→    45→  KS: [14, 165, 233, 255],   // Sky-500
    46→    46→  ALSTOM: [139, 92, 246, 255], // Violet-500
    47→    47→  DEFAULT: [100, 116, 139, 255], // Slate-500
    48→    48→};
    49→    49→
    50→    50→// =============================================================================
    51→    51→// Helper Functions
    52→    52→// =============================================================================
    53→    53→
    54→    54→/**
    55→    55→ * Transform API data into heatmap cells with positions
    56→    56→ */
    57→    57→function transformToHeatmapCells(
    58→    58→  data: StrategicCanvasData,
    59→    59→  fromYear: number,
    60→    60→  toYear: number
    61→    61→): HeatmapCell[] {
    62→    62→  const cells: HeatmapCell[] = [];
    63→    63→  const { trains, heatmapData } = data;
    64→    64→  const maxPmCount = heatmapData.maxPmCount || 1;
    65→    65→
    66→    66→  trains.forEach((train, trainIndex) => {
    67→    67→    for (let year = fromYear; year <= toYear; year++) {
    68→    68→      const yearIndex = year - fromYear;
    69→    69→      const yearData = train.years.find((y) => y.year === year);
    70→    70→
    71→    71→      const pmCount = yearData?.pmCount ?? 0;
    72→    72→      const totalHours = yearData?.totalHours ?? 0;
    73→    73→      const completedCount = yearData?.completedCount ?? 0;
    74→    74→      const lockedCount = yearData?.lockedCount ?? 0;
    75→    75→
    76→    76→      const intensity = Math.min(pmCount / maxPmCount, 1);
    77→    77→
    78→    78→      const x = LABEL_WIDTH + yearIndex * (CELL_WIDTH + CELL_PADDING);
    79→    79→      const y = HEADER_HEIGHT + trainIndex * (CELL_HEIGHT + CELL_PADDING);
    80→    80→
    81→    81→      cells.push({
    82→    82→        trainId: train.trainId,
    83→    83→        trainNumber: train.trainNumber,
    84→    84→        trainIndex,
    85→    85→        year,
    86→    86→        yearIndex,
    87→    87→        pmCount,
    88→    88→        totalHours,
    89→    89→        completedCount,
    90→    90→        lockedCount,
    91→    91→        intensity,
    92→    92→        position: [x + CELL_WIDTH / 2, y + CELL_HEIGHT / 2],
    93→    93→      });
    94→    94→    }
    95→    95→  });
    96→    96→
    97→    97→  return cells;
    98→    98→}
    99→    99→
   100→   100→/**
   101→   101→ * Get color for PM density
   102→   102→ */
   103→   103→function getDensityColor(intensity: number): [number, number, number, number] {
   104→   104→  const index = Math.min(
   105→   105→    Math.floor(intensity * (PM_DENSITY_COLORS.length - 1)),
   106→   106→    PM_DENSITY_COLORS.length - 1
   107→   107→  );
   108→   108→  return PM_DENSITY_COLORS[index];
   109→   109→}
   110→   110→
   111→   111→// =============================================================================
   112→   112→// Component Props
   113→   113→// =============================================================================
   114→   114→
   115→   115→export interface StrategicHeatmapProps {
   116→   116→  data: StrategicCanvasData | null;
   117→   117→  fromYear: number;
   118→   118→  toYear: number;
   119→   119→  width: number | string;
   120→   120→  height: number | string;
   121→   121→  onCellHover?: (cell: HeatmapCell | null) => void;
   122→   122→  onCellClick?: (cell: HeatmapCell) => void;
   123→   123→  onYearClick?: (year: number) => void;
   124→   124→}
   125→   125→
   126→   126→// =============================================================================
   127→   127→// Component
   128→   128→// =============================================================================
   129→   129→
   130→   130→/**
   131→   131→ * Strategic Heatmap View
   132→   132→ *
   133→   133→ * Renders a PM density heatmap using deck.gl WebGL layers.
   134→   134→ * Optimized for 60fps rendering of 100+ trains × 10 years.
   135→   135→ */
   136→   136→export function StrategicHeatmapLayer({
   137→   137→  data,
   138→   138→  fromYear,
   139→   139→  toYear,
   140→   140→  width,
   141→   141→  height,
   142→   142→  onCellHover,
   143→   143→  onCellClick,
   144→   144→  onYearClick,
   145→   145→}: StrategicHeatmapProps) {
   146→   146→  if (!data || data.trains.length === 0) {
   147→   147→    return (
   148→   148→      <div
   149→   149→        style={{
   150→   150→          width,
   151→   151→          height,
   152→   152→          display: 'flex',
   153→   153→          alignItems: 'center',
   154→   154→          justifyContent: 'center',
   155→   155→          color: 'var(--pt-text-muted)',
   156→   156→        }}
   157→   157→      >
   158→   158→        No strategic data available
   159→   159→      </div>
   160→   160→    );
   161→   161→  }
   162→   162→
   163→   163→  const cells = transformToHeatmapCells(data, fromYear, toYear);
   164→   164→  const yearCount = toYear - fromYear + 1;
   165→   165→  const trainCount = data.trains.length;
   166→   166→
   167→   167→  const canvasWidth = LABEL_WIDTH + yearCount * (CELL_WIDTH + CELL_PADDING) + 40;
   168→   168→  const canvasHeight = HEADER_HEIGHT + trainCount * (CELL_HEIGHT + CELL_PADDING) + 40;
   169→   169→
   170→   170→  const trainLabels = data.trains.map((train, index) => ({
   171→   171→    text: train.trainNumber,
   172→   172→    fleetCode: train.fleetCode,
   173→   173→    position: [LABEL_WIDTH / 2, HEADER_HEIGHT + index * (CELL_HEIGHT + CELL_PADDING) + CELL_HEIGHT / 2] as [number, number],
   174→   174→  }));
   175→   175→
   176→   176→  const yearLabels: Array<{ text: string; year: number; position: [number, number] }> = [];
   177→   177→  for (let year = fromYear; year <= toYear; year++) {
   178→   178→    const yearIndex = year - fromYear;
   179→   179→    yearLabels.push({
