   188→   188→
   189→   189→  const layers = [
   190→   190→    new ScatterplotLayer<HeatmapCell>({
   191→   191→      id: 'heatmap-cells',
   192→   192→      data: cells,
   193→   193→      pickable: true,
   194→   194→      opacity: 1,
   195→   195→      stroked: true,
   196→   196→      filled: true,
   197→   197→      radiusScale: 1,
   198→   198→      radiusMinPixels: 1,
   199→   199→      radiusMaxPixels: 100,
   200→   200→      lineWidthMinPixels: 1,
   201→   201→      getPosition: (d) => [...d.position, 0] as [number, number, number],
   202→   202→      getRadius: Math.min(CELL_WIDTH, CELL_HEIGHT) / 2 - 2,
   203→   203→      getFillColor: (d) => getDensityColor(d.intensity),
   204→   204→      getLineColor: [200, 200, 200, 255],
   205→   205→      getLineWidth: 1,
   206→   206→      onHover: (info) => {
   207→   207→        if (onCellHover) {
   208→   208→          onCellHover(info.object ?? null);
   209→   209→        }
   210→   210→      },
   211→   211→      onClick: (info) => {
   212→   212→        if (info.object && onCellClick) {
   213→   213→          onCellClick(info.object);
   214→   214→        }
   215→   215→      },
   216→   216→      updateTriggers: {
