   218→   218→      },
   219→   219→    }),
   220→   220→
   221→   221→    new TextLayer<{ text: string; fleetCode: string; position: [number, number] }>({
   222→   222→      id: 'train-labels',
   223→   223→      data: trainLabels,
   224→   224→      pickable: false,
   225→   225→      getPosition: (d) => [...d.position, 0] as [number, number, number],
   226→   226→      getText: (d) => d.text,
   227→   227→      getSize: 12,
   228→   228→      getAngle: 0,
   229→   229→      getTextAnchor: 'middle',
   230→   230→      getAlignmentBaseline: 'center',
   231→   231→      getColor: (d) => FLEET_COLORS[d.fleetCode] || FLEET_COLORS.DEFAULT,
   232→   232→      fontFamily: 'Inter, system-ui, sans-serif',
   233→   233→      fontWeight: 600,
   234→   234→    }),
   235→   235→
   236→   236→    new TextLayer<{ text: string; year: number; position: [number, number] }>({
   237→   237→      id: 'year-labels',
   238→   238→      data: yearLabels,
   239→   239→      pickable: true,
   240→   240→      getPosition: (d) => [...d.position, 0] as [number, number, number],
   241→   241→      getText: (d) => d.text,
   242→   242→      getSize: 14,
   243→   243→      getAngle: 0,
   244→   244→      getTextAnchor: 'middle',
   245→   245→      getAlignmentBaseline: 'center',
   246→   246→      getColor: [30, 41, 59, 255],
