     1→     1→/**
     2→     2→ * MMS Infinite Canvas
     3→     3→ *
     4→     4→ * The main canvas component that renders PM schedule data at different zoom levels.
     5→     5→ * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
     6→     6→ *
     7→     7→ * Zoom Level Rendering:
     8→     8→ * - STRATEGIC (0-4): deck.gl WebGL heatmap
     9→     9→ * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
    10→    10→ * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
    11→    11→ * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
    12→    12→ * - DETAIL (16+): React DOM overlay
    13→    13→ *
    14→    14→ * Based on specs/006-user-interface.md Section 6.3.
    15→    15→ */
    16→    16→
    17→    17→import { useRef } from 'react';
    18→    18→import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';
    19→    19→
    20→    20→import { useCanvas, useCanvasData, useFleet, usePm, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData } from '../../store';
    21→    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→    22→import type { CanvasDataState } from '../../store/slices/canvas';
    23→    23→import type { FleetSliceState } from '../../store/slices/fleet';
    24→    24→import type { PmSliceState } from '../../store/slices/pm';
    25→    25→import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
    26→    26→import { DragConfirmationDialog } from './DragConfirmationDialog';
    27→    27→import { quickValidatePmMove, createDebouncedValidation, getPmMoveImpact, commitPmMove } from './utils';
    28→    28→
    29→    29→// Toaster helper for showing notifications
