   218→   218→  const handlePmDragStart = (pmId: string, sourceDate: string) => {
   219→   219→    // Find PM in tactical data
   220→   220→    const pm = tacticalData?.pmBlocks.find(p => p.pmId === pmId);
   221→   221→    if (!pm) return;
   222→   222→
   223→   223→    // Store drag info
   224→   224→    draggingPmRef.current = {
   225→   225→      pmId,
   226→   226→      pmCode: pm.pmCode,
   227→   227→      trainId: pm.trainId,
   228→   228→      trainNumber: pm.trainNumber,
   229→   229→      sourceDate,
   230→   230→      constraintStart: pm.constraintStart,
   231→   231→      constraintEnd: pm.constraintEnd,
   232→   232→      isLocked: pm.isLocked,
   233→   233→    };
   234→   234→
   235→   235→    // Initialize drag state in PM slice
   236→   236→    pmActions.startDrag({ pmId, sourceDate });
   237→   237→
   238→   238→    // Set initial validation (quick check)
   239→   239→    const quickResult = quickValidatePmMove({
   240→   240→      pmId,
   241→   241→      currentDate: sourceDate,
   242→   242→      targetDate: sourceDate,
   243→   243→      trainId: pm.trainId,
   244→   244→      constraintStart: pm.constraintStart,
   245→   245→      constraintEnd: pm.constraintEnd,
   246→   246→      isLocked: pm.isLocked,
   247→   247→    });
   248→   248→    dragValidationRef.current = quickResult;
   249→   249→    pmActions.setDragValidation({
   250→   250→      isValid: quickResult.isValid,
   251→   251→      message: quickResult.message,
   252→   252→      violations: quickResult.violations,
   253→   253→    });
   254→   254→  };
   255→   255→
   256→   256→  const handlePmDragMove = (pmId: string, targetDate: string) => {
   257→   257→    const dragInfo = draggingPmRef.current;
   258→   258→    if (!dragInfo || dragInfo.pmId !== pmId) return;
   259→   259→
   260→   260→    // Update target date in PM slice
   261→   261→    pmActions.updateDragTarget(targetDate);
   262→   262→
   263→   263→    // Quick client-side validation
   264→   264→    const quickResult = quickValidatePmMove({
   265→   265→      pmId,
   266→   266→      currentDate: dragInfo.sourceDate,
   267→   267→      targetDate,
   268→   268→      trainId: dragInfo.trainId,
   269→   269→      constraintStart: dragInfo.constraintStart,
   270→   270→      constraintEnd: dragInfo.constraintEnd,
   271→   271→      isLocked: dragInfo.isLocked,
   272→   272→    });
   273→   273→    dragValidationRef.current = quickResult;
   274→   274→    pmActions.setDragValidation({
   275→   275→      isValid: quickResult.isValid,
   276→   276→      message: quickResult.message,
   277→   277→      violations: quickResult.violations,
   278→   278→    });
   279→   279→
   280→   280→    // If quick validation passes, trigger debounced API validation
   281→   281→    if (quickResult.isValid && targetDate !== dragInfo.sourceDate) {
   282→   282→      debouncedValidationRef.current.validate({
   283→   283→        pmId,
   284→   284→        currentDate: dragInfo.sourceDate,
   285→   285→        targetDate,
   286→   286→        trainId: dragInfo.trainId,
   287→   287→      });
   288→   288→    }
   289→   289→  };
   290→   290→
   291→   291→  const handlePmDragEnd = async (pmId: string, targetDate: string) => {
   292→   292→    const dragInfo = draggingPmRef.current;
   293→   293→    if (!dragInfo || dragInfo.pmId !== pmId) {
   294→   294→      // Clear drag state
   295→   295→      pmActions.cancelDrag();
   296→   296→      draggingPmRef.current = null;
   297→   297→      return;
   298→   298→    }
   299→   299→
   300→   300→    // Cancel pending validation
   301→   301→    debouncedValidationRef.current.cancel();
   302→   302→
   303→   303→    // If no change, just cancel
   304→   304→    if (targetDate === dragInfo.sourceDate) {
   305→   305→      pmActions.cancelDrag();
   306→   306→      draggingPmRef.current = null;
   307→   307→      return;
   308→   308→    }
   309→   309→
   310→   310→    // Final quick validation
   311→   311→    const finalValidation = quickValidatePmMove({
   312→   312→      pmId,
   313→   313→      currentDate: dragInfo.sourceDate,
   314→   314→      targetDate,
   315→   315→      trainId: dragInfo.trainId,
   316→   316→      constraintStart: dragInfo.constraintStart,
   317→   317→      constraintEnd: dragInfo.constraintEnd,
   318→   318→      isLocked: dragInfo.isLocked,
   319→   319→    });
   320→   320→
   321→   321→    // If invalid, snap back and show toast
