   328→   328→        message: finalValidation.message || 'Cannot reschedule: constraint violation',
   329→   329→        timeout: 5000,
   330→   330→      });
   331→   331→      return;
   332→   332→    }
   333→   333→
   334→   334→    // Open confirmation dialog
   335→   335→    dragConfirmRef.current = {
   336→   336→      isOpen: true,
   337→   337→      pmId,
   338→   338→      pmCode: dragInfo.pmCode,
