   351→   351→        pmId,
   352→   352→        currentDate: dragInfo.sourceDate,
   353→   353→        targetDate,
   354→   354→        trainId: dragInfo.trainId,
   355→   355→      });
   356→   356→      dragConfirmRef.current = {
   357→   357→        ...dragConfirmRef.current,
   358→   358→        impact,
   359→   359→        isLoadingImpact: false,
   360→   360→      };
   361→   361→    } catch {
   362→   362→      dragConfirmRef.current = {
   363→   363→        ...dragConfirmRef.current,
   364→   364→        isLoadingImpact: false,
   365→   365→      };
   366→   366→    }
   367→   367→
   368→   368→    // Keep draggingPmRef for the confirmation dialog
   369→   369→  };
   370→   370→
   371→   371→  const handleDragConfirm = async () => {
   372→   372→    const confirmState = dragConfirmRef.current;
   373→   373→    const dragInfo = draggingPmRef.current;
   374→   374→
   375→   375→    if (!confirmState.pmId || !dragInfo) {
   376→   376→      handleDragCancel();
