   383→   383→        pmId: confirmState.pmId,
   384→   384→        currentDate: confirmState.sourceDate,
   385→   385→        targetDate: confirmState.targetDate,
   386→   386→        trainId: dragInfo.trainId,
   387→   387→        reason: 'Manual reschedule via canvas drag-and-drop',
   388→   388→      });
   389→   389→
   390→   390→      // Confirm move in PM slice (updates local state)
   391→   391→      pmActions.confirmMove(confirmState.pmId);
   392→   392→
   393→   393→      // Show success toast
   394→   394→      void showToast({
   395→   395→        intent: Intent.SUCCESS,
   396→   396→        icon: 'tick',
   397→   397→        message: `${confirmState.pmCode} rescheduled to ${confirmState.targetDate}`,
   398→   398→        timeout: 3000,
   399→   399→      });
   400→   400→
   401→   401→      // Reload tactical data to reflect changes
   402→   402→      handleLoadTacticalData();
   403→   403→    } catch (error) {
   404→   404→      // Reject move (revert to original date)
   405→   405→      pmActions.rejectMove(confirmState.pmId);
   406→   406→
   407→   407→      // Show error toast
   408→   408→      void showToast({
   409→   409→        intent: Intent.DANGER,
   410→   410→        icon: 'error',
   411→   411→        message: error instanceof Error ? error.message : 'Failed to reschedule PM',
   412→   412→        timeout: 5000,
   413→   413→      });
   414→   414→    } finally {
   415→   415→      // Close dialog and clear state
   416→   416→      dragConfirmRef.current = initialDragConfirmState;
   417→   417→      draggingPmRef.current = null;
   418→   418→    }
   419→   419→  };
