  1022→  1022→        cursor: isPanning ? 'grabbing' : 'grab',
  1023→  1023→      }}
  1024→  1024→      onWheel={handleWheel}
  1025→  1025→      onMouseDown={handleMouseDown}
  1026→  1026→      onMouseUp={handleMouseUp}
  1027→  1027→      onMouseLeave={handleMouseUp}
  1028→  1028→      onMouseMove={handleMouseMove}
  1029→  1029→    >
  1030→  1030→      <div
  1031→  1031→        style={{
  1032→  1032→          position: 'absolute',
  1033→  1033→          top: 0,
  1034→  1034→          left: 0,
  1035→  1035→          right: 0,
  1036→  1036→          bottom: 0,
  1037→  1037→          transform: `translate(${-canvasState.panX}px, ${-canvasState.panY}px)`,
  1038→  1038→          transition: isPanning ? 'none' : 'transform 0.1s ease-out',
  1039→  1039→        }}
  1040→  1040→      >
  1041→  1041→        {renderContent()}
  1042→  1042→      </div>
  1043→  1043→
  1044→  1044→      <div style={{
  1045→  1045→        position: 'absolute',
  1046→  1046→        top: '12px',
  1047→  1047→        right: '12px',
  1048→  1048→        zIndex: 10,
  1049→  1049→      }}>
  1050→  1050→        <Card elevation={1} style={{ padding: '8px 12px' }}>
  1051→  1051→          <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
  1052→  1052→            Zoom Level
  1053→  1053→          </div>
  1054→  1054→          <div style={{ fontSize: '14px', fontWeight: 600 }}>
  1055→  1055→            {zoomLevel.replace('_', ' ')}
  1056→  1056→          </div>
  1057→  1057→          <div style={{ fontSize: '11px', fontFamily: 'monospace' }}>
  1058→  1058→            {zoom.toFixed(1)} / 20
  1059→  1059→          </div>
  1060→  1060→        </Card>
  1061→  1061→      </div>
  1062→  1062→
  1063→  1063→      <div style={{
  1064→  1064→        position: 'absolute',
  1065→  1065→        bottom: '12px',
  1066→  1066→        left: '12px',
  1067→  1067→        zIndex: 10,
  1068→  1068→      }}>
  1069→  1069→        <Card elevation={1} style={{ padding: '8px 12px' }}>
  1070→  1070→          <div style={{ fontSize: '11px' }}>
  1071→  1071→            <span style={{ color: 'var(--pt-text-muted)' }}>Viewport: </span>
  1072→  1072→            <span style={{ fontFamily: 'monospace' }}>
  1073→  1073→              {viewport.startDate} to {viewport.endDate}
  1074→  1074→            </span>
  1075→  1075→          </div>
  1076→  1076→          <div style={{ fontSize: '11px' }}>
  1077→  1077→            <span style={{ color: 'var(--pt-text-muted)' }}>Trains: </span>
  1078→  1078→            <span>{viewport.trainIds.length || 'All'}</span>
  1079→  1079→          </div>
  1080→  1080→        </Card>
  1081→  1081→      </div>
  1082→  1082→
  1083→  1083→      {(canvasState.layers.manhourOverlay || canvasState.layers.driftOverlay || canvasState.layers.baselineShadow) && (
  1084→  1084→        <div style={{
  1085→  1085→          position: 'absolute',
  1086→  1086→          top: '12px',
  1087→  1087→          left: '12px',
  1088→  1088→          zIndex: 10,
  1089→  1089→          display: 'flex',
  1090→  1090→          gap: '4px',
  1091→  1091→        }}>
  1092→  1092→          {canvasState.layers.manhourOverlay && (
  1093→  1093→            <Tag intent="primary" icon="chart">Man-hours</Tag>
  1094→  1094→          )}
  1095→  1095→          {canvasState.layers.driftOverlay && (
  1096→  1096→            <Tag intent="warning" icon="delta">Drift</Tag>
  1097→  1097→          )}
  1098→  1098→          {canvasState.layers.baselineShadow && (
  1099→  1099→            <Tag minimal icon="git-commit">Baseline</Tag>
  1100→  1100→          )}
  1101→  1101→        </div>
  1102→  1102→      )}
  1103→  1103→
  1104→  1104→      {/* Drag Confirmation Dialog */}
  1105→  1105→      <DragConfirmationDialog
  1106→  1106→        isOpen={dragConfirmRef.current.isOpen}
  1107→  1107→        pmCode={dragConfirmRef.current.pmCode}
  1108→  1108→        trainNumber={dragConfirmRef.current.trainNumber}
  1109→  1109→        sourceDate={dragConfirmRef.current.sourceDate}
  1110→  1110→        targetDate={dragConfirmRef.current.targetDate}
  1111→  1111→        impact={dragConfirmRef.current.impact}
  1112→  1112→        violations={pmState.drag.constraintViolations}
  1113→  1113→        isLoading={dragConfirmRef.current.isLoadingImpact}
  1114→  1114→        onConfirm={handleDragConfirm}
  1115→  1115→        onCancel={handleDragCancel}
  1116→  1116→      />
  1117→  1117→    </div>
  1118→  1118→  );
  1119→  1119→}
