     1→/**
     2→ * MMS Infinite Canvas
     3→ *
     4→ * The main canvas component that renders PM schedule data at different zoom levels.
     5→ * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
     6→ *
     7→ * Zoom Level Rendering:
     8→ * - STRATEGIC (0-4): deck.gl WebGL heatmap
     9→ * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
    10→ * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
    11→ * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
    12→ * - DETAIL (16+): React DOM overlay
    13→ *
    14→ * Based on specs/006-user-interface.md Section 6.3.
    15→ */
    16→
    17→import { useRef } from 'react';
    18→import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';
    19→
    20→import { useCanvas, useCanvasData, useFleet, usePm, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData } from '../../store';
    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→import type { CanvasDataState } from '../../store/slices/canvas';
    23→import type { FleetSliceState } from '../../store/slices/fleet';
    24→import type { PmSliceState } from '../../store/slices/pm';
    25→import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
    26→import { DragConfirmationDialog } from './DragConfirmationDialog';
    27→import { quickValidatePmMove, createDebouncedValidation, getPmMoveImpact, commitPmMove } from './utils';
    28→
    29→// Toaster helper for showing notifications
    30→// Uses the static show method which handles async creation
    31→async function showToast(options: {
    32→  intent: typeof Intent[keyof typeof Intent];
    33→  icon: 'error' | 'tick' | 'warning-sign' | 'info-sign';
    34→  message: string;
    35→  timeout: number;
    36→}): Promise<void> {
    37→  const toaster = await OverlayToaster.createAsync({ position: Position.TOP_RIGHT });
    38→  toaster.show(options);
    39→}
    40→
    41→/** Default canvas dimensions when container size is not available */
    42→const DEFAULT_CANVAS_WIDTH = 1200;
    43→const DEFAULT_CANVAS_HEIGHT = 800;
    44→
    45→// Drag confirmation state interface
    46→interface DragConfirmState {
    47→  isOpen: boolean;
    48→  pmId: string | null;
    49→  pmCode: string;
    50→  trainNumber: string;
    51→  sourceDate: string;
    52→  targetDate: string;
    53→  impact: PmMoveImpact | null;
    54→  isLoadingImpact: boolean;
    55→}
    56→
    57→const initialDragConfirmState: DragConfirmState = {
    58→  isOpen: false,
    59→  pmId: null,
    60→  pmCode: '',
    61→  trainNumber: '',
    62→  sourceDate: '',
    63→  targetDate: '',
    64→  impact: null,
    65→  isLoadingImpact: false,
    66→};
    67→
    68→export function InfiniteCanvas() {
    69→  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
    70→  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
    71→  const { state: fleetStateRaw } = useFleet();
    72→  const { state: pmStateRaw, actions: pmActions } = usePm();
    73→
    74→  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
    75→  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
    76→  const fleetState = fleetStateRaw as unknown as FleetSliceState;
    77→  const pmState = pmStateRaw as unknown as PmSliceState;
    78→
    79→  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
    80→  const {
    81→    strategicData, strategicLoading, strategicError, fromYear, toYear,
    82→    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
    83→    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate,
    84→    operationalData, operationalLoading, operationalError, operationalFromDate, operationalToDate,
    85→    detailData, detailLoading, detailError, detailFromDate, detailToDate, detailExpandedPmIds
    86→  } = canvasDataState;
    87→  const isLoading = fleetState.trains.length === 0;
    88→
    89→  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
    90→  const tooltipRef = useRef<HTMLDivElement>(null);
    91→
    92→  // Drag state refs
    93→  const dragValidationRef = useRef<DragValidationState | null>(null);
    94→  const draggingPmRef = useRef<{
    95→    pmId: string;
    96→    pmCode: string;
    97→    trainId: string;
    98→    trainNumber: string;
    99→    sourceDate: string;
   100→    constraintStart: string;
   101→    constraintEnd: string;
   102→    isLocked: boolean;
   103→  } | null>(null);
   104→  const dragConfirmRef = useRef<DragConfirmState>(initialDragConfirmState);
   105→
   106→  // Create debounced API validation
   107→  const debouncedValidationRef = useRef(
   108→    createDebouncedValidation((result) => {
   109→      dragValidationRef.current = result;
   110→      if (draggingPmRef.current) {
   111→        pmActions.setDragValidation({
   112→          isValid: result.isValid,
   113→          message: result.message,
   114→          violations: result.violations,
   115→        });
   116→      }
   117→    }, { delay: 150 })
   118→  );
   119→
   120→  const handleWheel = (event: React.WheelEvent) => {
   121→    event.preventDefault();
   122→    const delta = event.deltaY > 0 ? -0.5 : 0.5;
   123→    const newZoom = Math.max(0, Math.min(20, zoom + delta));
   124→    canvasActions.setZoom(newZoom);
   125→  };
   126→
   127→  const handleMouseDown = (event: React.MouseEvent) => {
   128→    if (event.button === 0) {
   129→      canvasActions.startPanning();
   130→    }
   131→  };
   132→
   133→  const handleMouseUp = () => {
   134→    canvasActions.stopPanning();
   135→  };
   136→
   137→  const handleMouseMove = (event: React.MouseEvent) => {
   138→    if (isPanning) {
   139→      canvasActions.pan({
   140→        dx: -event.movementX,
   141→        dy: -event.movementY,
   142→      });
   143→    }
   144→    tooltipPosRef.current = { x: event.clientX, y: event.clientY };
   145→  };
   146→
   147→  const handleLoadStrategicData = () => {
   148→    loadStrategicData(canvasDataActions, {
   149→      fromYear,
   150→      toYear,
   151→    });
   152→  };
   153→
   154→  const handleLoadTacticalWideData = () => {
   155→    loadTacticalWideData(canvasDataActions, {
   156→      fromDate: tacticalWideFromDate,
   157→      toDate: tacticalWideToDate,
   158→    });
   159→  };
   160→
   161→  const handleLoadTacticalData = () => {
   162→    loadTacticalData(canvasDataActions, {
   163→      fromWeek: tacticalFromDate,
   164→      toWeek: tacticalToDate,
   165→    });
   166→  };
   167→
   168→  const handleLoadOperationalData = () => {
   169→    loadOperationalData(canvasDataActions, {
   170→      fromDate: operationalFromDate,
   171→      toDate: operationalToDate,
   172→    });
   173→  };
   174→
   175→  const handleLoadDetailData = () => {
   176→    loadDetailData(canvasDataActions, {
   177→      fromDate: detailFromDate,
   178→      toDate: detailToDate,
   179→    });
   180→  };
   181→
   182→  const handleDetailPmSelect = (pmId: string) => {
   183→    canvasActions.selectPm(pmId);
   184→  };
   185→
   186→  const handleDetailPmExpand = (pmId: string) => {
   187→    canvasDataActions.expandDetailPm(pmId);
   188→  };
   189→
   190→  const handleDetailPmCollapse = (pmId: string) => {
   191→    canvasDataActions.collapseDetailPm(pmId);
   192→  };
   193→
   194→  const handleDetailPmEdit = (pmId: string, field: string) => {
   195→    // In production, this would dispatch an edit action to the PM service
   196→    console.log(`Edit PM ${pmId} field ${field}`);
   197→  };
   198→
   199→  const handleDetailPmLock = (pmId: string) => {
   200→    // In production, this would dispatch a lock action
   201→    console.log(`Lock PM ${pmId}`);
   202→  };
   203→
   204→  const handleDetailPmUnlock = (pmId: string) => {
   205→    // In production, this would dispatch an unlock action
   206→    console.log(`Unlock PM ${pmId}`);
   207→  };
   208→
   209→  const handleDetailViewHistory = (pmId: string) => {
   210→    // In production, this would open a history panel
   211→    console.log(`View history for PM ${pmId}`);
   212→  };
   213→
   214→  // ==========================================================================
   215→  // Drag-and-Drop Handlers
   216→  // ==========================================================================
   217→
   218→  const handlePmDragStart = (pmId: string, sourceDate: string) => {
   219→    // Find PM in tactical data
   220→    const pm = tacticalData?.pmBlocks.find(p => p.pmId === pmId);
   221→    if (!pm) return;
   222→
   223→    // Store drag info
   224→    draggingPmRef.current = {
   225→      pmId,
   226→      pmCode: pm.pmCode,
   227→      trainId: pm.trainId,
   228→      trainNumber: pm.trainNumber,
   229→      sourceDate,
   230→      constraintStart: pm.constraintStart,
   231→      constraintEnd: pm.constraintEnd,
   232→      isLocked: pm.isLocked,
   233→    };
   234→
   235→    // Initialize drag state in PM slice
   236→    pmActions.startDrag({ pmId, sourceDate });
   237→
   238→    // Set initial validation (quick check)
   239→    const quickResult = quickValidatePmMove({
   240→      pmId,
   241→      currentDate: sourceDate,
   242→      targetDate: sourceDate,
   243→      trainId: pm.trainId,
   244→      constraintStart: pm.constraintStart,
   245→      constraintEnd: pm.constraintEnd,
   246→      isLocked: pm.isLocked,
   247→    });
   248→    dragValidationRef.current = quickResult;
   249→    pmActions.setDragValidation({
   250→      isValid: quickResult.isValid,
   251→      message: quickResult.message,
   252→      violations: quickResult.violations,
   253→    });
   254→  };
   255→
   256→  const handlePmDragMove = (pmId: string, targetDate: string) => {
   257→    const dragInfo = draggingPmRef.current;
   258→    if (!dragInfo || dragInfo.pmId !== pmId) return;
   259→
   260→    // Update target date in PM slice
   261→    pmActions.updateDragTarget(targetDate);
   262→
   263→    // Quick client-side validation
   264→    const quickResult = quickValidatePmMove({
   265→      pmId,
   266→      currentDate: dragInfo.sourceDate,
   267→      targetDate,
   268→      trainId: dragInfo.trainId,
   269→      constraintStart: dragInfo.constraintStart,
   270→      constraintEnd: dragInfo.constraintEnd,
   271→      isLocked: dragInfo.isLocked,
   272→    });
   273→    dragValidationRef.current = quickResult;
   274→    pmActions.setDragValidation({
   275→      isValid: quickResult.isValid,
   276→      message: quickResult.message,
   277→      violations: quickResult.violations,
   278→    });
   279→
   280→    // If quick validation passes, trigger debounced API validation
   281→    if (quickResult.isValid && targetDate !== dragInfo.sourceDate) {
   282→      debouncedValidationRef.current.validate({
   283→        pmId,
   284→        currentDate: dragInfo.sourceDate,
   285→        targetDate,
   286→        trainId: dragInfo.trainId,
   287→      });
   288→    }
   289→  };
   290→
   291→  const handlePmDragEnd = async (pmId: string, targetDate: string) => {
   292→    const dragInfo = draggingPmRef.current;
   293→    if (!dragInfo || dragInfo.pmId !== pmId) {
   294→      // Clear drag state
   295→      pmActions.cancelDrag();
   296→      draggingPmRef.current = null;
   297→      return;
   298→    }
   299→
   300→    // Cancel pending validation
   301→    debouncedValidationRef.current.cancel();
   302→
   303→    // If no change, just cancel
   304→    if (targetDate === dragInfo.sourceDate) {
   305→      pmActions.cancelDrag();
   306→      draggingPmRef.current = null;
   307→      return;
   308→    }
   309→
   310→    // Final quick validation
   311→    const finalValidation = quickValidatePmMove({
   312→      pmId,
   313→      currentDate: dragInfo.sourceDate,
   314→      targetDate,
   315→      trainId: dragInfo.trainId,
   316→      constraintStart: dragInfo.constraintStart,
   317→      constraintEnd: dragInfo.constraintEnd,
   318→      isLocked: dragInfo.isLocked,
   319→    });
   320→
   321→    // If invalid, snap back and show toast
   322→    if (!finalValidation.isValid) {
   323→      pmActions.cancelDrag();
   324→      draggingPmRef.current = null;
   325→      void showToast({
   326→        intent: Intent.DANGER,
   327→        icon: 'error',
   328→        message: finalValidation.message || 'Cannot reschedule: constraint violation',
   329→        timeout: 5000,
   330→      });
   331→      return;
   332→    }
   333→
   334→    // Open confirmation dialog
   335→    dragConfirmRef.current = {
   336→      isOpen: true,
   337→      pmId,
   338→      pmCode: dragInfo.pmCode,
   339→      trainNumber: dragInfo.trainNumber,
   340→      sourceDate: dragInfo.sourceDate,
   341→      targetDate,
   342→      impact: null,
   343→      isLoadingImpact: true,
   344→    };
   345→    // Force re-render by ending drag with commit=false (optimistic update)
   346→    pmActions.endDrag(false);
   347→
   348→    // Load impact assessment
   349→    try {
   350→      const impact = await getPmMoveImpact({
   351→        pmId,
   352→        currentDate: dragInfo.sourceDate,
   353→        targetDate,
   354→        trainId: dragInfo.trainId,
   355→      });
   356→      dragConfirmRef.current = {
   357→        ...dragConfirmRef.current,
   358→        impact,
   359→        isLoadingImpact: false,
   360→      };
   361→    } catch {
   362→      dragConfirmRef.current = {
   363→        ...dragConfirmRef.current,
   364→        isLoadingImpact: false,
   365→      };
   366→    }
   367→
   368→    // Keep draggingPmRef for the confirmation dialog
   369→  };
   370→
   371→  const handleDragConfirm = async () => {
   372→    const confirmState = dragConfirmRef.current;
   373→    const dragInfo = draggingPmRef.current;
   374→
   375→    if (!confirmState.pmId || !dragInfo) {
   376→      handleDragCancel();
   377→      return;
   378→    }
   379→
   380→    try {
   381→      // Commit the move to API
   382→      await commitPmMove({
   383→        pmId: confirmState.pmId,
   384→        currentDate: confirmState.sourceDate,
   385→        targetDate: confirmState.targetDate,
   386→        trainId: dragInfo.trainId,
   387→        reason: 'Manual reschedule via canvas drag-and-drop',
   388→      });
   389→
   390→      // Confirm move in PM slice (updates local state)
   391→      pmActions.confirmMove(confirmState.pmId);
   392→
   393→      // Show success toast
   394→      void showToast({
   395→        intent: Intent.SUCCESS,
   396→        icon: 'tick',
   397→        message: `${confirmState.pmCode} rescheduled to ${confirmState.targetDate}`,
   398→        timeout: 3000,
   399→      });
   400→
   401→      // Reload tactical data to reflect changes
   402→      handleLoadTacticalData();
   403→    } catch (error) {
   404→      // Reject move (revert to original date)
   405→      pmActions.rejectMove(confirmState.pmId);
   406→
   407→      // Show error toast
   408→      void showToast({
   409→        intent: Intent.DANGER,
   410→        icon: 'error',
   411→        message: error instanceof Error ? error.message : 'Failed to reschedule PM',
   412→        timeout: 5000,
   413→      });
   414→    } finally {
   415→      // Close dialog and clear state
   416→      dragConfirmRef.current = initialDragConfirmState;
   417→      draggingPmRef.current = null;
   418→    }
   419→  };
   420→
   421→  const handleDragCancel = () => {
   422→    const confirmState = dragConfirmRef.current;
   423→
   424→    // Revert the move if pending
   425→    if (confirmState.pmId) {
   426→      pmActions.rejectMove(confirmState.pmId);
   427→    }
   428→
   429→    // Clear state
   430→    dragConfirmRef.current = initialDragConfirmState;
   431→    draggingPmRef.current = null;
   432→  };
   433→
   434→  const handlePmBlockHover = (pm: PmBlock | null) => {
   435→    if (tooltipRef.current) {
   436→      if (pm) {
   437→        tooltipRef.current.style.display = 'block';
   438→        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
   439→        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
   440→        tooltipRef.current.innerHTML = `
   441→          <div style="font-weight: 600; margin-bottom: 4px;">
   442→            ${pm.pmCode} - ${pm.trainNumber}
   443→          </div>
   444→          <div style="color: #64748b;">
   445→            <div>Date: <strong>${pm.targetDate}</strong></div>
   446→            <div>Duration: <strong>${pm.durationDays} day${pm.durationDays > 1 ? 's' : ''}</strong></div>
   447→            <div>Status: <strong>${pm.status}</strong></div>
   448→            ${pm.depotCode ? `<div>Depot: <strong>${pm.depotCode}</strong></div>` : ''}
